export const Appointments = () => {
  const [viewMode, setViewMode] = useState<'queue' | 'list'>('queue');
  const [selectedDate, setSelectedDate] = useState(new Date());
  const [appointments, setAppointments] = useState<Appointment[]>([]);
  const [patients, setPatients] = useState<Patient[]>([]);
  const [staff, setStaff] = useState<MedicalStaff[]>([]);
  const [departments, setDepartments] = useState<any[]>([]);
  const { user: currentUser } = useAuth();
  const [loading, setLoading] = useState(true);
  const [filterDept, setFilterDept] = useState('all');
  const { t } = useTranslation();

  // Process State
  const [processStatus, setProcessStatus] = useState<'idle' | 'processing' | 'success' | 'error'>('idle');
  const [processMessage, setProcessMessage] = useState('');

  // Modals
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isCancelConfirmOpen, setIsCancelConfirmOpen] = useState(false);
  const [appointmentToCancel, setAppointmentToCancel] = useState<number | null>(null);
  const [editingAppointment, setEditingAppointment] = useState<Appointment | null>(null);
  const [isEditing, setIsEditing] = useState(false);
  const [editingForm, setEditingForm] = useState({
    patientId: '',
    staffId: '',
    date: formatDate(selectedDate),
    time: '09:00',
    type: 'Consultation',
    reason: '',
  });

  const checkAvailability = (doc: MedicalStaff, dateStr: string) => {
    if (doc.status !== 'active') return false;
    if (!doc.availableDays || doc.availableDays.length === 0) return true; // Assume available if not specified
    try {
        const scheduleDays = doc.availableDays.map((d: string) => d.toLowerCase());
        // To get weekday correctly across timezones, add T00:00:00 to parse as local time.
        const appointmentDate = new Date(dateStr + 'T00:00:00');
        const weekday = appointmentDate.toLocaleDateString('en-US', { weekday: 'short' }).toLowerCase();
        return scheduleDays.includes(weekday);
    } catch (e) {
        console.error("Date parsing error for availability check:", e);
        return true; // Default to available on error
    }
  };

  const loadData = async (isBackground = false) => {
    if (!isBackground) setLoading(true);
    try {
      const [apts, pts, stf, depts] = await Promise.all([
        api.getAppointments(),
        api.getPatients(),
        api.getStaff(),
        api.getDepartments(),
      ]);
      setAppointments(Array.isArray(apts) ? apts : []);
      setPatients(Array.isArray(pts) ? pts : []);
      setStaff(Array.isArray(stf) ? stf : []);
      setDepartments(Array.isArray(depts) ? depts : []);
    } catch (e) {
      console.error("Failed to load appointment data", e);
    } finally {
      if (!isBackground) setLoading(false);
    }
  };

  useEffect(() => {
    loadData();
  }, []);


  const dailyAppointments = useMemo(() => {
    // 1. Filter appointments for the day
    const appointmentsForDay = appointments.filter(apt => {
        if (!apt || !apt.datetime) return false;
        return isSameDay(new Date(apt.datetime), selectedDate);
    });

    // 2. Filter by Department if needed
    const filteredByDept = appointmentsForDay.filter(apt => {
        return filterDept === 'all' || staff.find(s => s.id === apt.staffId)?.department === filterDept;
    });

    // 3. Group by Staff ID
    const groupedByStaff: Record<string, Appointment[]> = {};
    filteredByDept.forEach(apt => {
        if (!groupedByStaff[apt.staffId]) groupedByStaff[apt.staffId] = [];
        groupedByStaff[apt.staffId].push(apt);
    });

    // 4. Sort and Assign Token Per Staff
    const statusPriority: Record<string, number> = {
      'in_progress': 0, 'confirmed': 1, 'checked_in': 2, 'waiting': 3, 'pending': 4,
      'completed': 6, 'cancelled': 7
    };

    const finalGrouped: Record<string, Appointment[]> = {};

    Object.keys(groupedByStaff).forEach(staffId => {
        const staffAppts = groupedByStaff[staffId];

        // Sort for token assignment: Time based
        const sortedForToken = [...staffAppts].sort((a,b) => (a.datetime && b.datetime) ? new Date(a.datetime).getTime() - new Date(b.datetime).getTime() : 0);

        // Assign Token (1...N)
        const withTokens = sortedForToken.map((apt, index) => ({
            ...apt,
            dailyToken: index + 1
        }));

        // Sort for display (Priority)
        const sortedForDisplay = [...withTokens].sort((a, b) => {
            if (!a || !b) return 0;
            // Prioritize by status first
            const statusA = statusPriority[a.status] ?? 99;
            const statusB = statusPriority[b.status] ?? 99;
            if (statusA !== statusB) return statusA - statusB;
            // Then by time 
            return (a.datetime && b.datetime) ? new Date(a.datetime).getTime() - new Date(b.datetime).getTime() : 0;
        });

        finalGrouped[staffId] = sortedForDisplay;
    });

    return finalGrouped;
  }, [appointments, selectedDate, filterDept, staff]);

  const activeStaff = useMemo(() => {
    const activeStaffIds = new Set(Object.keys(dailyAppointments));
    return staff.filter(s => activeStaffIds.has(s.id.toString()));
  }, [dailyAppointments, staff]);

  const openModal = () => {
    setIsEditing(false);
    setEditingAppointment(null);
    setEditingForm({
      patientId: '',
      staffId: '',
      date: formatDate(selectedDate),
      time: '09:00',
      type: 'Consultation',
      reason: ''
    });
    setIsModalOpen(true);
  };

  const openEditModal = (apt: Appointment) => {
    if (!apt) return;
    setEditingAppointment(apt);
    setIsEditing(true);
    setEditingForm({
      patientId: apt?.patientId.toString() || '',
      staffId: apt?.staffId.toString() || '',
      date: apt && apt.datetime ? formatDate(new Date(apt.datetime)) : formatDate(selectedDate),
      time: apt && apt.datetime ? new Date(apt.datetime).toTimeString().slice(0, 5) : '09:00',
      type: apt.type,
      reason: apt.reason || '',
    });
    setIsModalOpen(true);
  };

  const handleCreateAppointment = async (e: React.FormEvent) => {
    e.preventDefault();
    setProcessStatus('processing');
    setProcessMessage(isEditing ? t('appointments_process_updating') : t('appointments_process_creating'));

    const payload = {
      ...editingForm,
      datetime: `${editingForm.date}T${editingForm.time}`,
      patientId: parseInt(editingForm.patientId),
      staffId: parseInt(editingForm.staffId),
    };

    try {
      if (isEditing && editingAppointment) {
        // Simple edit: cancel old, create new. More complex logic could be PUT request.
        await api.cancelAppointment(editingAppointment.id);
        await api.createAppointment(payload);
      } else {
        await api.createAppointment(payload);
      }

      setProcessStatus('success');
      setProcessMessage(isEditing ? t('appointments_process_update_success') : t('appointments_process_create_success'));

      setIsModalOpen(false);
      await loadData(true);

      setTimeout(() => {
        setProcessStatus('idle');
      }, 1500);

    } catch (e: any) {
      setProcessStatus('error');
      setProcessMessage(e.response?.data?.error || t('appointments_process_save_fail'));
    }
  };

  const handleStatusUpdate = async (id: number, status: string) => {
    await api.updateAppointmentStatus(id, status);
    await loadData(true);
  };

  const confirmCancel = (id: number) => {
    setAppointmentToCancel(id);
    setIsCancelConfirmOpen(true);
  };

  const handleCancel = async () => {
    if (!appointmentToCancel) return;

    setProcessStatus('processing');
    setProcessMessage(t('appointments_process_cancelling'));

    try {
      await api.cancelAppointment(appointmentToCancel);

      setProcessStatus('success');
      setProcessMessage(t('appointments_process_cancel_success'));

      await loadData(true);
    } catch (e: any) {
      setProcessStatus('error');
      setProcessMessage(e.response?.data?.error || t('appointments_process_cancel_fail'));
    } finally {
      setIsCancelConfirmOpen(false);
      setAppointmentToCancel(null);
      setTimeout(() => setProcessStatus('idle'), 1500);
    }
  };

  const changeDate = (offset: number) => {
    setSelectedDate(prev => {
      const newDate = new Date(prev);
      newDate.setDate(newDate.getDate() + offset);
      return newDate;
    });
  };

  const canManage = hasPermission(currentUser, Permissions.MANAGE_APPOINTMENTS);

  // Sort overall list by time only, ignoring doctor groups, for the ListView
  const listAllAppointments = Object.values(dailyAppointments).flat().sort((a: Appointment, b: Appointment) => 
    (a.datetime && b.datetime) ? new Date(a.datetime).getTime() - new Date(b.datetime).getTime() : 0
  );

  return (
    <div className="space-y-6">

      {/* Process Status Overlay */}
      {processStatus !== 'idle' && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center bg-black/60 backdrop-blur-sm animate-in fade-in duration-200">
            <div className="bg-white dark:bg-slate-900 p-8 rounded-3xl shadow-2xl flex flex-col items-center max-w-sm w-full mx-4 text-center">
                {processStatus === 'processing' && <Loader2 className="w-12 h-12 text-primary-600 animate-spin mb-4" />}
                {processStatus === 'success' && <CheckCircle className="w-12 h-12 text-green-600 mb-4" />}
                {processStatus === 'error' && <XCircle className="w-12 h-12 text-red-600 mb-4" />}
                <p className="font-medium text-slate-700 dark:text-slate-200 mb-4">{processMessage}</p>
                {processStatus === 'error' && (
                  <Button variant="secondary" onClick={() => setProcessStatus('idle')} className="w-full">{t('close')}</Button>
                )}
            </div>
        </div>
      )}

      {/* Header & Controls */}
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div>
          <h1 className="text-2xl font-bold text-gray-900 dark:text-white">{t('appointments_title')}</h1>
          <p className="text-sm text-slate-500 dark:text-slate-400">{t('appointments_subtitle')}</p>
        </div>
        <div className="flex gap-3">
          {canManage && <Button onClick={openModal} icon={Plus}>{t('appointments_new_walkin_button')}</Button>}
        </div>
      </div>

      {/* Toolbar */}
      <Card className="!p-3 flex flex-col sm:flex-row justify-between items-center gap-4 shadow-sm">
        <div className="flex items-center gap-2">
          <Button variant="ghost" size="sm" onClick={() => changeDate(-1)} icon={ChevronLeft} className="!p-2 h-10 w-10" />
          <div className="text-center">
            <h3 className="font-bold text-lg text-slate-800 dark:text-white">{selectedDate.toLocaleDateString([], { weekday: 'long' })}</h3>
            <p className="text-sm text-slate-500">{selectedDate.toLocaleDateString()}</p>
          </div>
          <Button variant="ghost" size="sm" onClick={() => changeDate(1)} icon={ChevronRight} className="!p-2 h-10 w-10" />
          <Button variant="outline" size="sm" onClick={() => setSelectedDate(new Date())} className="ml-2">{t('dashboard_today')}</Button>
        </div>

        <div className="flex items-center gap-2">
           <Select value={filterDept} onChange={e => setFilterDept(e.target.value)}>
             <option value="all">{t('appointments_filter_all_depts')}</option>
             {departments.map(d => <option key={d.id} value={d.name_en}>{d.name_en}</option>)}
           </Select>
           <div className="p-1 bg-slate-100 dark:bg-slate-800 rounded-lg flex gap-1">
             <Button variant={viewMode === 'queue' ? 'secondary' : 'ghost'} size="sm" onClick={() => setViewMode('queue')} icon={LayoutGrid} className={viewMode === 'queue' ? 'bg-white dark:bg-slate-700 shadow-sm' : ''}>{t('appointments_view_queue')}</Button>
             <Button variant={viewMode === 'list' ? 'secondary' : 'ghost'} size="sm" onClick={() => setViewMode('list')} icon={ListIcon} className={viewMode === 'list' ? 'bg-white dark:bg-slate-700 shadow-sm' : ''}>{t('appointments_view_list')}</Button>
           </div>
        </div>
      </Card>

      {/* Main Content */}
      {viewMode === 'queue' ? (
        <div className="flex gap-4 overflow-x-auto pb-4 custom-scrollbar -mx-8 px-8">
          {loading ? <p>{t('loading')}</p> :
           activeStaff.length === 0 ? <p className="text-slate-400 mx-auto py-10">{t('appointments_queue_no_staff')}</p> :
           activeStaff.map(doc => (
            <DoctorQueueColumn 
              key={doc.id} 
              doctor={doc} 
              appointments={dailyAppointments[doc.id] || []}
              onStatusUpdate={handleStatusUpdate}
              onCancel={confirmCancel}
              canManage={canManage}
            />
          ))}
        </div>
      ) : (
        <Card className="!p-0 animate-in fade-in">
           <ListView appointments={listAllAppointments} onEdit={openEditModal} onCancel={confirmCancel} canManage={canManage} />
        </Card>
      )}

      {/* Appointment Modal */}
      <Modal isOpen={isModalOpen} onClose={() => setIsModalOpen(false)} title={isEditing ? t('appointments_modal_edit_title') : t('appointments_modal_title')}>
        <form onSubmit={handleCreateAppointment} className="space-y-4">
          <Select 
            label={t('appointments_form_select_patient')} 
            required 
            value={editingForm.patientId} 
            onChange={e => setEditingForm({...editingForm, patientId: e.target.value})}
            disabled={isEditing}
          >
            <option value="">{t('appointments_form_select_patient')}</option>
            {patients.map(p => <option key={p.id} value={p.id}>{p.fullName} ({p.patientId})</option>)}
          </Select>

          <Select 
            label={t('appointments_form_select_staff')} 
            required 
            value={editingForm.staffId} 
            onChange={e => setEditingForm({...editingForm, staffId: e.target.value})}
          >
            <option value="">{t('appointments_form_select_staff')}</option>
            {staff
              .filter(s => (s.type === 'doctor' || s.type === 'nurse') && checkAvailability(s, editingForm.date))
              .map(s => (
                <option key={s.id} value={s.id}>{s.fullName} - {s.type === 'nurse' ? t('appointments_form_select_nurse') : s.specialization}</option>
            ))}
          </Select>

          <div className="grid grid-cols-2 gap-4">
            <Input label="Date" type="date" required value={editingForm.date} onChange={e => setEditingForm({...editingForm, date: e.target.value})} />
            <Input label={t('appointments_form_time')} type="time" required value={editingForm.time} onChange={e => setEditingForm({...editingForm, time: e.target.value})} />
          </div>

          <Select label={t('appointments_form_type')} value={editingForm.type} onChange={e => setEditingForm({...editingForm, type: e.target.value})}>
            <option>Consultation</option>
            <option>Follow-up</option>
            <option>Emergency</option>
            <option>Procedure</option>
          </Select>

          <Textarea label={t('appointments_form_reason')} value={editingForm.reason} onChange={e => setEditingForm({...editingForm, reason: e.target.value})} />

          <div className="flex justify-end pt-4 gap-3 border-t dark:border-slate-700">
            <Button type="button" variant="secondary" onClick={() => setIsModalOpen(false)}>{t('cancel')}</Button>
            <Button type="submit">{isEditing ? t('appointments_form_update_button') : t('appointments_form_create_button')}</Button>
          </div>
        </form>
      </Modal>

      {/* Cancel Confirmation */}
      <ConfirmationDialog 
        isOpen={isCancelConfirmOpen}
        onClose={() => setIsCancelConfirmOpen(false)}
        onConfirm={handleCancel}
        title={t('appointments_cancel_dialog_title')}
        message={<p>{t('appointments_cancel_dialog_message')}</p>}
      />
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { Card, Button, Input, Select, Modal, Badge, Textarea } from '../components/UI';
import { 
  Plus, Printer, Download, X, Lock, CreditCard, 
  Wallet, TrendingUp, AlertCircle, FileText, CheckCircle, Trash2,
  ChevronLeft, ChevronRight, ChevronsLeft, ChevronsRight, Search, Filter, Calendar,
  Landmark, ArrowUpRight, ArrowDownRight, RefreshCcw, Loader2
} from 'lucide-react';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip as RechartsTooltip, Legend, ResponsiveContainer 
} from 'recharts';
import { api } from '../services/api';
import { Bill, Patient, Appointment, PaymentMethod, TaxRate, Transaction, InsuranceProvider } from '@/types';
import { hasPermission, Permissions } from '../utils/rbac';
import { useTranslation } from '../context/TranslationContext';
import { useAuth } from '../context/AuthContext';

export const Billing = () => {
  const { t, language } = useTranslation();
  const [activeTab, setActiveTab] = useState<'invoices' | 'treasury'>('invoices');
  const [bills, setBills] = useState<Bill[]>([]);
  const [patients, setPatients] = useState<Patient[]>([]);
  const [paymentMethods, setPaymentMethods] = useState<PaymentMethod[]>([]);
  const [taxRates, setTaxRates] = useState<TaxRate[]>([]);
  const [catalogItems, setCatalogItems] = useState<{label: string, cost: number}[]>([]);
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [insuranceProviders, setInsuranceProviders] = useState<InsuranceProvider[]>([]);

  const [loading, setLoading] = useState(true);
  const [isProcessing, setIsProcessing] = useState(false);
  const { user: currentUser } = useAuth();

  // Pagination & Filtering State
  const [currentPage, setCurrentPage] = useState(1);
  const [itemsPerPage, setItemsPerPage] = useState(10);
  const [searchTerm, setSearchTerm] = useState('');
  const [filterType, setFilterType] = useState('all');
  const [dateRange, setDateRange] = useState({ start: '', end: '' });

  // Separate Treasury Filters
  const [treasurySearch, setTreasurySearch] = useState('');
  const [treasuryFilter, setTreasuryFilter] = useState('all');
  const [treasuryDate, setTreasuryDate] = useState({ start: '', end: '' });
  const [treasuryPage, setTreasuryPage] = useState(1);

  // Stats
  const [stats, setStats] = useState({
    totalRevenue: 0,
    pendingAmount: 0,
    paidInvoices: 0
  });

  // Treasury Stats
  const [treasuryStats, setTreasuryStats] = useState({
    income: 0,
    expenses: 0,
    net: 0
  });

  // Modals
  const [isCreateModalOpen, setIsCreateModalOpen] = useState(false);
  const [isPaymentModalOpen, setIsPaymentModalOpen] = useState(false);
  const [isExpenseModalOpen, setIsExpenseModalOpen] = useState(false);
  const [isRefundModalOpen, setIsRefundModalOpen] = useState(false);

  const [selectedBill, setSelectedBill] = useState<Bill | null>(null); // For Invoice View
  const [payingBill, setPayingBill] = useState<Bill | null>(null); // For Payment Action
  const [refundingBill, setRefundingBill] = useState<Bill | null>(null); // For Refund Action

  // Create Invoice Form
  const [createForm, setCreateForm] = useState({
    patientId: '',
    items: [{ description: '', amount: '' }],
    selectedTaxId: ''
  });

  // Payment Form State
  const [paymentForm, setPaymentForm] = useState({
    amount: '',
    method: '', // Dynamic
    date: new Date().toISOString().split('T')[0],
    notes: '',
    // Insurance specific
    insuranceProvider: '',
    policyNumber: '',
    expiryDate: '',
    // Transaction specific
    transactionId: ''
  });

  // Refund Form State
  const [refundForm, setRefundForm] = useState({
    amount: '',
    method: 'Cash',
    reason: 'Service Cancelled',
    date: new Date().toISOString().split('T')[0],
    customReason: ''
  });

  // Expense Form State
  const [expenseForm, setExpenseForm] = useState({
    category: 'General',
    amount: '',
    method: 'Cash',
    date: new Date().toISOString().split('T')[0],
    description: ''
  });

  const loadData = async () => {
    setLoading(true);
    try {
      const [b, p, pm, taxes, labs, services, trans, ins] = await Promise.all([
        api.getBills(), 
        api.getPatients(),
        api.getPaymentMethods(),
        api.getTaxRates(),
        api.getLabTests(),
        api.getNurseServices(),
        api.getTransactions(),
        api.getInsuranceProviders()
      ]);
      setBills(Array.isArray(b) ? b : []);
      setPatients(Array.isArray(p) ? p : []);
      setPaymentMethods(Array.isArray(pm) ? pm : []);
      setTaxRates(Array.isArray(taxes) ? taxes : []);
      setTransactions(Array.isArray(trans) ? trans : []);
      setInsuranceProviders(Array.isArray(ins) ? ins : []);

      // Build Catalog
      const catalog = [
        ...(Array.isArray(labs) ? labs.map((l: any) => ({ label: `Lab: ${l.name_en}`, cost: l.cost })) : []),
        ...(Array.isArray(services) ? services.map((s: any) => ({ label: `Service: ${s.name_en}`, cost: s.cost })) : [])
      ];
      setCatalogItems(catalog);

      // Calculate Invoice Stats
      const total = b.reduce((acc: number, curr: Bill) => acc + (curr.paidAmount || 0), 0);
      const pending = b.reduce((acc: number, curr: Bill) => acc + ((curr.totalAmount || 0) - (curr.paidAmount || 0)), 0);
      const paidCount = b.filter((x: Bill) => x.status === 'paid').length;

      setStats({
        totalRevenue: total,
        pendingAmount: pending,
        paidInvoices: paidCount
      });

      // Calculate Treasury Stats
      const income = trans.filter((t: any) => t.type === 'income').reduce((sum: number, t: any) => sum + t.amount, 0);
      const expense = trans.filter((t: any) => t.type === 'expense').reduce((sum: number, t: any) => sum + t.amount, 0);
      setTreasuryStats({ income, expenses: expense, net: income - expense });

    } catch (e) {
      console.error(e);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    loadData();
  }, []);

  // --- Handlers ---

  const handleAddItem = () => {
    setCreateForm({
      ...createForm,
      items: [...createForm.items, { description: '', amount: '' }]
    });
  };

  const handleRemoveItem = (index: number) => {
    const newItems = createForm.items.filter((_, i) => i !== index);
    setCreateForm({ ...createForm, items: newItems });
  };

  const handleItemChange = (index: number, field: 'description' | 'amount', value: string) => {
    const newItems = [...createForm.items];
    newItems[index] = { ...newItems[index], [field]: value };
    setCreateForm({ ...createForm, items: newItems });
  };

  const handleCatalogSelect = (index: number, value: string) => {
    if (!value) return;
    const item = catalogItems.find(i => i.label === value);
    if (item) {
        const newItems = [...createForm.items];
        newItems[index] = { description: item.label, amount: item.cost.toString() };
        setCreateForm({ ...createForm, items: newItems });
    }
  };

  const handleCreateSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    const patient = patients.find(p => p.id === parseInt(createForm.patientId));

    // Filter out empty rows and format
    let formattedItems = createForm.items
      .filter(i => i.description && i.amount)
      .map(i => ({ description: i.description, amount: parseFloat(i.amount) }));

    if (patient && formattedItems.length > 0) {
      setIsProcessing(true);
      let total = formattedItems.reduce((sum, i) => sum + i.amount, 0);

      // Apply Tax if selected
      if (createForm.selectedTaxId) {
          const tax = taxRates.find(t => t.id === parseInt(createForm.selectedTaxId));
          if (tax) {
              const taxAmount = (total * tax.rate) / 100;
              formattedItems.push({
                  description: `Tax: ${tax.name_en} (${tax.rate}%)`,
                  amount: parseFloat(taxAmount.toFixed(2))
              });
              total += taxAmount;
          }
      }

      try {
        await api.createBill({
          patientId: patient.id,
          patientName: patient.fullName,
          totalAmount: total,
          date: new Date().toISOString().split('T')[0],
          items: formattedItems
        });

        setIsCreateModalOpen(false);
        setCreateForm({ patientId: '', items: [{ description: '', amount: '' }], selectedTaxId: '' });
        loadData();
      } catch(e) {
        console.error(e);
      } finally {
        setIsProcessing(false);
      }
    }
  };

  const openPaymentModal = (bill: Bill) => {
    setPayingBill(bill);
    const patient = patients.find(p => p.id === bill.patientId);

    // Default to remaining balance
    const remaining = bill.totalAmount - (bill.paidAmount || 0);

    // Smart Pre-fill: Check insurance
    const hasInsurance = patient?.hasInsurance;

    // Try to find default method
    const defaultMethod = hasInsurance ? 'Insurance' : (paymentMethods.length > 0 ? paymentMethods[0].name_en : 'Cash');

    setPaymentForm({ 
        amount: remaining.toString(), 
        method: defaultMethod,
        date: new Date().toISOString().split('T')[0],
        notes: '',
        transactionId: '',
        insuranceProvider: hasInsurance ? patient?.insuranceDetails?.provider || '' : '',
        policyNumber: hasInsurance ? patient?.insuranceDetails?.policyNumber || '' : '',
        expiryDate: hasInsurance ? patient?.insuranceDetails?.expiryDate || '' : ''
    });
    setIsPaymentModalOpen(true);
  };

  const handlePaymentSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!payingBill) return;
    setIsProcessing(true);

    // Construct Payment Payload
    const payload: any = {
        amount: parseFloat(paymentForm.amount),
        method: paymentForm.method,
        date: paymentForm.date,
        details: { notes: paymentForm.notes }
    };

    if (paymentForm.method === 'Insurance') {
        payload.details = {
            ...payload.details,
            provider: paymentForm.insuranceProvider,
            policyNumber: paymentForm.policyNumber,
            expiryDate: paymentForm.expiryDate
        };
    } else if (paymentForm.method !== 'Cash') {
        payload.details = {
            ...payload.details,
            transactionId: paymentForm.transactionId
        };
    }

    try {
      await api.recordPayment(payingBill.id, payload);
      setIsPaymentModalOpen(false);
      setPayingBill(null);
      loadData();
    } catch (e) {
      alert('Payment failed');
    } finally {
      setIsProcessing(false);
    }
  };

  const openRefundModal = (bill: Bill) => {
    setRefundingBill(bill);
    // Default to fully paid amount
    setRefundForm({
        amount: bill.paidAmount.toString(),
        method: 'Cash',
        reason: 'Service Cancelled',
        date: new Date().toISOString().split('T')[0],
        customReason: ''
    });
    setIsRefundModalOpen(true);
  };

  const handleRefundSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!refundingBill) return;
    setIsProcessing(true);

    try {
        const finalReason = refundForm.reason === 'Other' ? refundForm.customReason : refundForm.reason;

        await api.processRefund(refundingBill.id, {
            amount: parseFloat(refundForm.amount),
            method: refundForm.method,
            reason: finalReason,
            date: refundForm.date
        });
        setIsRefundModalOpen(false);
        setRefundingBill(null);
        loadData();
    } catch (e) {
        alert('Refund failed');
    } finally {
        setIsProcessing(false);
    }
  };

  const handleExpenseSubmit = async (e: React.FormEvent) => {
      e.preventDefault();
      setIsProcessing(true);
      try {
          await api.addExpense({
              ...expenseForm,
              amount: parseFloat(expenseForm.amount)
          });
          setIsExpenseModalOpen(false);
          setExpenseForm({ category: 'General', amount: '', method: 'Cash', date: new Date().toISOString().split('T')[0], description: '' });
          loadData();
      } catch(e) {
          alert('Failed to add expense');
      } finally {
          setIsProcessing(false);
      }
  };

  // --- Helper to derive Bill Type ---
  const getBillType = (bill: Bill): string => {
    // Scan items to determine type based on descriptions generated by backend controllers
    const desc = bill.items?.map(i => i.description.toLowerCase()).join(' ') || '';

    if (desc.includes('admission') || desc.includes('accommodation') || desc.includes('deposit')) return 'Admission';
    if (desc.includes('surgery') || desc.includes('operation')) return 'Operation';
    if (desc.includes('lab') || desc.includes('test')) return 'Lab Test';
    if (desc.includes('appointment') || desc.includes('consultation') || desc.includes('follow-up')) return 'Appointment';
    if (desc.includes('service') || desc.includes('procedure') || desc.includes('dressing') || desc.includes('injection')) return 'Procedure';

    return 'General';
  };

  const getTypeColor = (type: string) => {
    switch (type) {
      case 'Admission': return 'orange';
      case 'Operation': return 'red';
      case 'Lab Test': return 'purple';
      case 'Appointment': return 'blue';
      case 'Procedure': return 'cyan';
      default: return 'gray';
    }
  };

  const translateBillType = (type: string) => {
      switch(type) {
          case 'Admission': return t('billing_type_admission');
          case 'Operation': return t('billing_type_operation');
          case 'Lab Test': return t('billing_type_lab');
          case 'Appointment': return t('billing_type_appointment');
          case 'Procedure': return t('billing_type_procedure');
          default: return t('billing_type_general');
      }
  };

  // --- Filtering & Pagination Logic (Bills) ---
  const filteredBills = useMemo(() => {
    return bills.filter(bill => {
      const matchesSearch = 
        bill.patientName.toLowerCase().includes(searchTerm.toLowerCase()) ||
        bill.billNumber.toLowerCase().includes(searchTerm.toLowerCase());

      const billType = getBillType(bill);
      const matchesType = filterType === 'all' || billType === filterType;

      let matchesDate = true;
      if (dateRange.start) {
        matchesDate = matchesDate && new Date(bill.date) >= new Date(dateRange.start);
      }
      if (dateRange.end) {
        const endDate = new Date(dateRange.end);
        endDate.setHours(23, 59, 59, 999);
        matchesDate = matchesDate && new Date(bill.date) <= endDate;
      }

      return matchesSearch && matchesType && matchesDate;
    });
  }, [bills, searchTerm, filterType, dateRange]);

  const totalPages = Math.ceil(filteredBills.length / itemsPerPage);
  const paginatedBills = filteredBills.slice((currentPage - 1) * itemsPerPage, currentPage * itemsPerPage);

  // --- Filtering & Pagination Logic (Treasury) ---
  const filteredTransactions = useMemo(() => {
    return transactions.filter(t => {
        const matchesSearch = 
            (t.description && t.description.toLowerCase().includes(treasurySearch.toLowerCase())) ||
            (t.category && t.category.toLowerCase().includes(treasurySearch.toLowerCase()));

        const matchesType = treasuryFilter === 'all' || t.type === treasuryFilter;

        let matchesDate = true;
        if (treasuryDate.start) {
            matchesDate = matchesDate && new Date(t.date) >= new Date(treasuryDate.start);
        }
        if (treasuryDate.end) {
            const endDate = new Date(treasuryDate.end);
            endDate.setHours(23, 59, 59, 999);
            matchesDate = matchesDate && new Date(t.date) <= endDate;
        }

        return matchesSearch && matchesType && matchesDate;
    });
  }, [transactions, treasurySearch, treasuryFilter, treasuryDate]);

  // Aggregate daily data for chart
  const treasuryChartData = useMemo(() => {
    const dailyMap = new Map<string, {name: string, income: number, expense: number}>();

    // Sort transactions by date asc for chart
    const sortedTrans = [...filteredTransactions].sort((a,b) => new Date(a.date).getTime() - new Date(b.date).getTime());

    sortedTrans.forEach(t => {
        const day = new Date(t.date).toLocaleDateString('en-US', { month: 'short', day: 'numeric' });
        if (!dailyMap.has(day)) {
            dailyMap.set(day, { name: day, income: 0, expense: 0 });
        }
        const entry = dailyMap.get(day)!;
        if (t.type === 'income') entry.income += t.amount;
        else entry.expense += t.amount;
    });

    return Array.from(dailyMap.values());
  }, [filteredTransactions]);

  const totalTreasuryPages = Math.ceil(filteredTransactions.length / itemsPerPage);
  const paginatedTransactions = filteredTransactions.slice((treasuryPage - 1) * itemsPerPage, treasuryPage * itemsPerPage);


  // --- Render Helpers ---

  const InvoiceView = ({ bill }: { bill: Bill }) => {
    // Try to find Tax Item
    const taxItem = bill.items.find(i => i.description.toLowerCase().startsWith('tax'));
    const subtotal = bill.items.filter(i => !i.description.toLowerCase().startsWith('tax')).reduce((sum, i) => sum + i.amount, 0);
    const taxAmount = taxItem ? taxItem.amount : 0;
    const hospitalName = localStorage.getItem('hospital_name') || 'AllCare Hospital';

    return (
        <div className="p-10 bg-white min-h-[600px] text-slate-800" id="invoice-print">
        {/* Header */}
        <div className="flex justify-between items-start border-b-2 border-slate-100 pb-8 mb-8">
            <div>
            <div className="flex items-center gap-2 mb-2">
                <div className="bg-primary-600 text-white p-2 rounded-lg"><Wallet size={24}/></div>
                <h1 className="text-2xl font-bold text-slate-900">{t('billing_invoice_title')}</h1>
            </div>
            <p className="text-slate-500 font-mono">#{bill.billNumber}</p>
            <div className="mt-4 flex gap-2">
                <span className={`px-3 py-1 rounded-full text-xs font-bold uppercase tracking-wider ${bill.status === 'paid' ? 'bg-green-100 text-green-700' : bill.status === 'refunded' ? 'bg-purple-100 text-purple-700' : 'bg-red-100 text-red-700'}`}>
                    {bill.status}
                </span>
                <span className="px-3 py-1 rounded-full text-xs font-bold uppercase tracking-wider bg-slate-100 text-slate-600">
                    {translateBillType(getBillType(bill))}
                </span>
            </div>
            </div>
            <div className="text-right">
            <h2 className="text-xl font-bold text-primary-600">{hospitalName}</h2>
            <p className="text-sm text-slate-500 mt-1">123 Health Ave, Med City</p>
            <p className="text-sm text-slate-500">contact@allcare.com</p>
            <p className="text-sm text-slate-500">+1 (555) 012-3456</p>
            </div>
        </div>

        {/* Client Info */}
        <div className="flex justify-between mb-10">
            <div>
            <p className="text-xs text-slate-400 font-bold uppercase tracking-wider mb-1">{t('billing_invoice_billed_to')}</p>
            <p className="font-bold text-lg text-slate-900">{bill.patientName}</p>
            <p className="text-slate-500 text-sm">Patient ID: #{bill.patientId}</p>
            </div>
            <div className="text-right">
            <p className="text-xs text-slate-400 font-bold uppercase tracking-wider mb-1">{t('billing_invoice_date')}</p>
            <p className="font-medium text-slate-900">{new Date(bill.date).toLocaleDateString()}</p>
            </div>
        </div>

        {/* Line Items */}
        <table className="w-full mb-8">
            <thead>
            <tr className="bg-slate-50 border-y border-slate-200">
                <th className="text-left py-3 px-4 font-semibold text-sm text-slate-600">{t('billing_modal_create_item_placeholder')}</th>
                <th className="text-right py-3 px-4 font-semibold text-sm text-slate-600">{t('billing_table_header_amount')}</th>
            </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
            {bill.items.map((item, i) => (
                <tr key={i}>
                <td className="py-3 px-4">{item.description}</td>
                <td className="py-3 px-4 text-right font-medium">${item.amount.toFixed(2)}</td>
                </tr>
            ))}
            </tbody>
        </table>

        {/* Totals */}
        <div className="flex justify-end">
            <div className="w-full max-w-xs space-y-3">
            <div className="flex justify-between text-slate-600">
                <span>{t('billing_invoice_subtotal')}</span>
                <span className="font-medium">${subtotal.toFixed(2)}</span>
            </div>
            {taxAmount > 0 && (
                <div className="flex justify-between text-slate-600">
                    <span>{t('billing_invoice_tax')}</span>
                    <span className="font-medium">${taxAmount.toFixed(2)}</span>
                </div>
            )}
            <div className="flex justify-between text-slate-900 font-bold text-lg border-t-2 border-slate-200 pt-3 mt-2">
                <span>{t('billing_invoice_total')}</span>
                <span>${bill.totalAmount.toFixed(2)}</span>
            </div>
            <div className="flex justify-between text-green-600 font-bold text-sm pt-1">
                <span>{t('billing_invoice_paid')}</span>
                <span>-${(bill.paidAmount || 0).toFixed(2)}</span>
            </div>
            <div className="flex justify-between text-slate-900 font-bold text-xl bg-slate-100 p-3 rounded-lg">
                <span>{t('billing_invoice_balance')}</span>
                <span>${(bill.totalAmount - (bill.paidAmount || 0)).toFixed(2)}</span>
            </div>
            </div>
        </div>
        </div>
    );
  };

  const canManageBilling = hasPermission(currentUser, Permissions.MANAGE_BILLING);
  const isAccountant = currentUser?.role === 'accountant' || currentUser?.role === 'admin';

  // Refund condition logic
  const isRefundEnabled = (bill: Bill) => {
      // Logic: Enabled if service is NOT in progress (i.e. either not received or completed).
      // Disables only if service is actively happening (locking funds temporarily).
      if (!isAccountant) return false;
      const status = bill.serviceStatus;
      if (!status) return true; // Manual bills are refundable
      return !['in_progress', 'active'].includes(status);
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div>
          <h1 className="text-2xl font-bold text-gray-900 dark:text-white">{t('billing_title')}</h1>
          <p className="text-sm text-slate-500 dark:text-slate-400">{t('billing_subtitle')}</p>
        </div>
      </div>

      {/* Main Tabs */}
      <div className="flex bg-white dark:bg-slate-800 p-1 rounded-xl shadow-sm border border-slate-200 dark:border-slate-700 w-fit mb-6">
          {[
              { id: 'invoices', label: t('billing_tab_invoices') || 'Invoices', icon: FileText },
              { id: 'treasury', label: t('billing_tab_treasury') || 'Treasury', icon: Landmark },
          ].map(tab => (
              <button
                key={tab.id}
                onClick={() => setActiveTab(tab.id as any)}
                className={`flex items-center gap-2 px-6 py-2.5 rounded-lg text-sm font-bold transition-all ${activeTab === tab.id ? 'bg-primary-50 dark:bg-primary-900/20 text-primary-700 dark:text-primary-300 shadow-sm' : 'text-slate-500 hover:text-slate-700 dark:text-slate-400 dark:hover:text-slate-200'}`}
              >
                  <tab.icon size={18} />
                  {tab.label}
              </button>
          ))}
      </div>

      {activeTab === 'invoices' && (
        <>
            <div className="flex justify-end">
                {canManageBilling ? (
                    <Button onClick={() => setIsCreateModalOpen(true)} icon={Plus}>{t('billing_create_invoice_button')}</Button>
                ) : (
                    <Button disabled variant="secondary" icon={Lock}>{t('billing_create_invoice_button')}</Button>
                )}
            </div>

            {/* Stats Cards */}
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                <Card>
                <h4 className="text-xs font-bold text-slate-500 uppercase">{t('billing_stat_revenue')}</h4>
                <p className="text-3xl font-bold text-emerald-600 mt-2">${stats.totalRevenue.toLocaleString()}</p>
                </Card>
                <Card>
                <h4 className="text-xs font-bold text-slate-500 uppercase">{t('billing_stat_pending')}</h4>
                <p className="text-3xl font-bold text-orange-500 mt-2">${stats.pendingAmount.toLocaleString()}</p>
                </Card>
                <Card>
                <h4 className="text-xs font-bold text-slate-500 uppercase">{t('billing_stat_paid')}</h4>
                <p className="text-3xl font-bold text-slate-800 dark:text-white mt-2">{stats.paidInvoices}</p>
                </Card>
            </div>

            <Card className="!p-0 border border-slate-200 dark:border-slate-700 shadow-sm overflow-visible z-10">
                <div className="p-4 border-b border-slate-200 dark:border-slate-700 flex flex-col md:flex-row gap-4 items-start md:items-center justify-between">
                <div className="flex flex-col sm:flex-row gap-2 w-full md:w-auto">
                    <div className="relative w-full sm:w-64">
                        <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 w-4 h-4" />
                        <input 
                            type="text" 
                            placeholder={t('billing_search_placeholder')}
                            className="pl-9 pr-4 py-2 w-full rounded-lg border border-slate-300 dark:border-slate-600 bg-white dark:bg-slate-800 text-sm"
                            value={searchTerm}
                            onChange={e => { setSearchTerm(e.target.value); setCurrentPage(1); }}
                        />
                    </div>

                    <div className="relative w-full sm:w-auto">
                        <Filter className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 w-4 h-4 pointer-events-none" />
                        <select 
                            className="pl-9 pr-8 py-2 w-full rounded-lg border border-slate-300 dark:border-slate-600 bg-white dark:bg-slate-800 text-sm focus:ring-2 focus:ring-primary-500 outline-none appearance-none cursor-pointer"
                            value={filterType}
                            onChange={e => { setFilterType(e.target.value); setCurrentPage(1); }}
                        >
                            <option value="all">{t('patients_filter_type_all')}</option>
                            <option value="Appointment">{t('billing_type_appointment')}</option>
                            <option value="Lab Test">{t('billing_type_lab')}</option>
                            <option value="Admission">{t('billing_type_admission')}</option>
                            <option value="Operation">{t('billing_type_operation')}</option>
                            <option value="Procedure">{t('billing_type_procedure')}</option>
                            <option value="General">{t('billing_type_general')}</option>
                        </select>
                    </div>
                </div>

                {/* Date Range Filter */}
                <div className="flex items-center gap-2 w-full md:w-auto">
                    <Calendar className="text-slate-400 w-4 h-4 shrink-0" />
                    <input 
                        type="date" 
                        className="px-3 py-2 rounded-lg border border-slate-300 dark:border-slate-600 bg-white dark:bg-slate-800 text-sm w-full md:w-auto"
                        value={dateRange.start}
                        onChange={e => setDateRange({...dateRange, start: e.target.value})}
                        placeholder="Start"
                    />
                    <span className="text-slate-400">-</span>
                    <input 
                        type="date" 
                        className="px-3 py-2 rounded-lg border border-slate-300 dark:border-slate-600 bg-white dark:bg-slate-800 text-sm w-full md:w-auto"
                        value={dateRange.end}
                        onChange={e => setDateRange({...dateRange, end: e.target.value})}
                        placeholder="End"
                    />
                </div>
                </div>

                <div className="overflow-x-auto">
                <table className="min-w-full divide-y divide-slate-200 dark:divide-slate-700">
                    <thead className="bg-slate-50 dark:bg-slate-900">
                    <tr>
                        <th className="px-6 py-3 text-left text-xs font-bold text-slate-500 uppercase tracking-wider">{t('billing_table_header_info')}</th>
                        <th className="px-6 py-3 text-left text-xs font-bold text-slate-500 uppercase tracking-wider">{t('billing_table_header_patient')}</th>
                        <th className="px-6 py-3 text-left text-xs font-bold text-slate-500 uppercase tracking-wider">{t('appointments_form_type')}</th>
                        <th className="px-6 py-3 text-left text-xs font-bold text-slate-500 uppercase tracking-wider">{t('billing_table_header_status')}</th>
                        <th className="px-6 py-3 text-right text-xs font-bold text-slate-500 uppercase tracking-wider">{t('billing_table_header_amount')}</th>
                        <th className="px-6 py-3 text-right text-xs font-bold text-slate-500 uppercase tracking-wider">{t('billing_table_header_actions')}</th>
                    </tr>
                    </thead>
                    <tbody className="bg-white dark:bg-slate-800 divide-y divide-slate-200 dark:divide-slate-700">
                    {loading ? <tr><td colSpan={6} className="text-center py-10 text-slate-500">{t('billing_table_loading')}</td></tr> :
                    paginatedBills.length === 0 ? <tr><td colSpan={6} className="text-center py-10 text-slate-500">{t('billing_table_empty')}</td></tr> :
                    paginatedBills.map(bill => (
                        <tr key={bill.id}>
                        <td className="px-6 py-4 whitespace-nowrap">
                            <div className="font-mono text-sm font-medium text-slate-900 dark:text-white">{bill.billNumber}</div>
                            <div className="text-xs text-slate-500">{new Date(bill.date).toLocaleDateString()}</div>
                        </td>
                        <td className="px-6 py-4 whitespace-nowrap font-medium text-slate-800 dark:text-slate-200">{bill.patientName}</td>
                        <td className="px-6 py-4 whitespace-nowrap">
                            <Badge color={getTypeColor(getBillType(bill)) as any}>{translateBillType(getBillType(bill))}</Badge>
                        </td>
                        <td className="px-6 py-4 whitespace-nowrap">
                            <Badge color={bill.status === 'paid' ? 'green' : bill.status === 'refunded' ? 'purple' : bill.status === 'partial' ? 'yellow' : 'red'}>{bill.status}</Badge>
                        </td>
                        <td className="px-6 py-4 whitespace-nowrap text-right">
                            <div className="font-bold text-lg text-slate-900 dark:text-white">${bill.totalAmount.toLocaleString()}</div>
                            <div className="text-xs text-green-600">{t('billing_table_paid_amount')}: ${bill.paidAmount.toLocaleString()}</div>
                        </td>
                        <td className="px-6 py-4 whitespace-nowrap text-right text-sm font-medium flex justify-end gap-2">
                            <Button size="sm" variant="secondary" icon={FileText} onClick={() => setSelectedBill(bill)}>{t('billing_action_view_invoice')}</Button>

                            {canManageBilling && (
                                <>
                                    {(bill.status === 'pending' || bill.status === 'partial') && (
                                        <Button size="sm" onClick={() => openPaymentModal(bill)}>{t('billing_action_pay')}</Button>
                                    )}
                                    {bill.status === 'paid' && (
                                        <Button 
                                            size="sm" 
                                            variant="danger" 
                                            disabled={!isRefundEnabled(bill)} 
                                            icon={RefreshCcw}
                                            title={!isAccountant ? "Refunds require Accountant role" : (!isRefundEnabled(bill) ? "Cannot refund active service" : "")}
                                            onClick={() => isRefundEnabled(bill) && openRefundModal(bill)}
                                        >
                                            Refund
                                        </Button>
                                    )}
                                </>
                            )}
                        </td>
                        </tr>
                    ))}
                    </tbody>
                </table>
                </div>
            </Card>
        </>
      )}

      {/* ... Treasury Tab remains similar, skipping for brevity ... */}
      {activeTab === 'treasury' && (
          <div className="space-y-6 animate-in fade-in">
              <div className="flex justify-end">
                  <Button onClick={() => setIsExpenseModalOpen(true)} icon={Plus} variant="secondary">Record Expense</Button>
              </div>

              {/* Treasury Stats */}
              <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                  <Card>
                    <h4 className="text-xs font-bold text-slate-500 uppercase">Total Income</h4>
                    <p className="text-3xl font-bold text-green-600 mt-2 flex items-center gap-2"><ArrowUpRight size={24}/> ${treasuryStats.income.toLocaleString()}</p>
                  </Card>
                  <Card>
                    <h4 className="text-xs font-bold text-slate-500 uppercase">Total Expenses</h4>
                    <p className="text-3xl font-bold text-red-500 mt-2 flex items-center gap-2"><ArrowDownRight size={24}/> ${treasuryStats.expenses.toLocaleString()}</p>
                  </Card>
                  <Card>
                    <h4 className="text-xs font-bold text-slate-500 uppercase">Net Cash Flow</h4>
                    <p className={`text-3xl font-bold mt-2 ${treasuryStats.net >= 0 ? 'text-blue-600' : 'text-red-600'}`}>${treasuryStats.net.toLocaleString()}</p>
                  </Card>
              </div>

              {/* Cash Flow Chart - Recharts Visualization */}
              <div className="h-80 w-full bg-white dark:bg-slate-800 rounded-xl p-4 border border-slate-200 dark:border-slate-700 shadow-sm overflow-hidden">
                  <h3 className="font-bold text-slate-800 dark:text-white mb-4">Cash Flow Overview</h3>
                  <ResponsiveContainer width="100%" height="100%">
                    <BarChart data={treasuryChartData}>
                        <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#e2e8f0" className="dark:stroke-slate-700" />
                        <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#64748b', fontSize: 12}} />
                        <YAxis axisLine={false} tickLine={false} tick={{fill: '#64748b', fontSize: 12}} />
                        <RechartsTooltip 
                            cursor={{fill: 'transparent'}}
                            contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 12px rgba(0,0,0,0.1)', backgroundColor: '#fff', color: '#1e293b' }} 
                        />
                        <Legend />
                        <Bar dataKey="income" name="Income" fill="#10b981" radius={[4, 4, 0, 0]} barSize={20} />
                        <Bar dataKey="expense" name="Expenses" fill="#ef4444" radius={[4, 4, 0, 0]} barSize={20} />
                    </BarChart>
                  </ResponsiveContainer>
              </div>

              <Card className="!p-0 border border-slate-200 dark:border-slate-700 shadow-sm overflow-hidden">
                  <div className="p-4 bg-slate-50 dark:bg-slate-900 border-b border-slate-200 dark:border-slate-700 flex flex-col md:flex-row gap-4 items-center">
                      <div className="flex items-center gap-2 flex-1">
                          <Landmark size={18} className="text-slate-500"/> 
                          <h3 className="font-bold text-slate-800 dark:text-white">Recent Transactions</h3>
                      </div>
                      <div className="flex gap-2">
                          <input 
                            type="text" 
                            placeholder="Search..." 
                            className="px-3 py-1.5 rounded-lg border border-slate-300 dark:border-slate-600 bg-white dark:bg-slate-800 text-sm"
                            value={treasurySearch}
                            onChange={(e) => setTreasurySearch(e.target.value)}
                          />
                          <select 
                            className="px-3 py-1.5 rounded-lg border border-slate-300 dark:border-slate-600 bg-white dark:bg-slate-800 text-sm"
                            value={treasuryFilter}
                            onChange={(e) => setTreasuryFilter(e.target.value)}
                          >
                              <option value="all">All</option>
                              <option value="income">Income</option>
                              <option value="expense">Expense</option>
                          </select>
                          <input 
                            type="date" 
                            className="px-3 py-1.5 rounded-lg border border-slate-300 dark:border-slate-600 bg-white dark:bg-slate-800 text-sm"
                            value={treasuryDate.start}
                            onChange={(e) => setTreasuryDate({...treasuryDate, start: e.target.value})}
                          />
                      </div>
                  </div>
                  <div className="overflow-x-auto">
                      <table className="min-w-full divide-y divide-slate-200 dark:divide-slate-700">
                          <thead className="bg-white dark:bg-slate-900">
                              <tr>
                                  <th className="px-6 py-3 text-left text-xs font-bold text-slate-500 uppercase">Date</th>
                                  <th className="px-6 py-3 text-left text-xs font-bold text-slate-500 uppercase">Type</th>
                                  <th className="px-6 py-3 text-left text-xs font-bold text-slate-500 uppercase">Category</th>
                                  <th className="px-6 py-3 text-left text-xs font-bold text-slate-500 uppercase">Description</th>
                                  <th className="px-6 py-3 text-left text-xs font-bold text-slate-500 uppercase">Method</th>
                                  <th className="px-6 py-3 text-right text-xs font-bold text-slate-500 uppercase">Amount</th>
                              </tr>
                          </thead>
                          <tbody className="divide-y divide-slate-100 dark:divide-slate-700 bg-white dark:bg-slate-800">
                              {paginatedTransactions.map((t) => (
                                  <tr key={t.id}>
                                      <td className="px-6 py-3 text-sm text-slate-600 dark:text-slate-300">{new Date(t.date).toLocaleDateString()}</td>
                                      <td className="px-6 py-3">
                                          <Badge color={t.type === 'income' ? 'green' : 'red'}>{t.type}</Badge>
                                      </td>
                                      <td className="px-6 py-3 text-sm font-medium">{t.category || '-'}</td>
                                      <td className="px-6 py-3 text-sm text-slate-500">{t.description}</td>
                                      <td className="px-6 py-3 text-sm">{t.method}</td>
                                      <td className={`px-6 py-3 text-sm font-bold text-right ${t.type === 'income' ? 'text-green-600' : 'text-red-600'}`}>
                                          {t.type === 'income' ? '+' : '-'}${t.amount.toLocaleString()}
                                      </td>
                                  </tr>
                              ))}
                          </tbody>
                      </table>
                  </div>
                  {/* Pagination Footer */}
                  <div className="px-6 py-3 border-t border-slate-200 dark:border-slate-700 flex justify-between items-center">
                      <span className="text-sm text-slate-500">Page {treasuryPage} of {totalTreasuryPages || 1}</span>
                      <div className="flex gap-2">
                          <button onClick={() => setTreasuryPage(p => Math.max(1, p - 1))} disabled={treasuryPage === 1} className="p-1 rounded hover:bg-slate-100 disabled:opacity-50"><ChevronLeft size={16}/></button>
                          <button onClick={() => setTreasuryPage(p => Math.min(totalTreasuryPages, p + 1))} disabled={treasuryPage === totalTreasuryPages} className="p-1 rounded hover:bg-slate-100 disabled:opacity-50"><ChevronRight size={16}/></button>
                      </div>
                  </div>
              </Card>
          </div>
      )}

      {/* MODALS */}
      <Modal isOpen={isCreateModalOpen} onClose={() => setIsCreateModalOpen(false)} title={t('billing_modal_create_title')}>
        <form onSubmit={handleCreateSubmit} className="space-y-4">
          <Select 
            label={t('billing_modal_create_select_patient')}
            value={createForm.patientId}
            onChange={e => setCreateForm({...createForm, patientId: e.target.value})}
            required
          >
            <option value="">{t('billing_modal_create_choose_patient')}</option>
            {patients.map(p => <option key={p.id} value={p.id}>{p.fullName}</option>)}
          </Select>

          <div>
            <label className="block text-sm font-semibold text-slate-700 dark:text-slate-300 mb-1.5">{t('billing_modal_create_items_label')}</label>
            <div className="space-y-2 max-h-60 overflow-y-auto pr-1 custom-scrollbar">
              {createForm.items.map((item, index) => (
                <div key={index} className="flex flex-col sm:flex-row gap-2 items-start sm:items-center bg-slate-50 dark:bg-slate-900 p-2 rounded-lg">
                  {/* Catalog Selector */}
                  <select 
                    className="w-full sm:w-1/3 text-xs p-2 rounded border border-slate-300 dark:border-slate-700 bg-white dark:bg-slate-800"
                    onChange={(e) => handleCatalogSelect(index, e.target.value)}
                    defaultValue=""
                  >
                    <option value="" disabled>Quick Add...</option>
                    {catalogItems.map((c, i) => <option key={i} value={c.label}>{c.label}</option>)}
                  </select>

                  <Input 
                    placeholder={t('billing_modal_create_item_placeholder')}
                    value={item.description}
                    onChange={e => handleItemChange(index, 'description', e.target.value)}
                    className="flex-1"
                  />
                  <div className="flex gap-2 w-full sm:w-auto">
                    <Input 
                        placeholder="0.00"
                        type="number"
                        value={item.amount}
                        onChange={e => handleItemChange(index, 'amount', e.target.value)}
                        className="w-24"
                    />
                    <button type="button" onClick={() => handleRemoveItem(index)} className="text-red-500 hover:text-red-700 p-2">
                        <Trash2 size={16}/>
                    </button>
                  </div>
                </div>
              ))}
            </div>
            <Button size="sm" variant="secondary" onClick={handleAddItem} className="mt-2 w-full" icon={Plus}>{t('billing_modal_create_add_item_button')}</Button>
          </div>

          <div className="grid grid-cols-2 gap-4 border-t pt-4">
             <div>
                <label className="block text-sm font-semibold text-slate-700 dark:text-slate-300 mb-1">Tax Rate</label>
                <select 
                    className="w-full rounded-xl border border-slate-300 dark:border-slate-700 bg-white dark:bg-slate-900 p-2 text-sm"
                    value={createForm.selectedTaxId}
                    onChange={e => setCreateForm({...createForm, selectedTaxId: e.target.value})}
                >
                    <option value="">None</option>
                    {taxRates.filter(t => t.isActive).map(t => (
                        <option key={t.id} value={t.id}>{language === 'ar' ? t.name_ar : t.name_en} ({t.rate}%)</option>
                    ))}
                </select>
             </div>
             <div className="text-right">
                <span className="block text-sm text-slate-500">{t('billing_modal_create_total_label')}</span>
                <span className="text-2xl font-bold text-slate-900 dark:text-white">
                    ${(() => {
                        const subtotal = createForm.items.reduce((sum, i) => sum + (parseFloat(i.amount) || 0), 0);
                        const taxRate = taxRates.find(t => t.id === parseInt(createForm.selectedTaxId));
                        const tax = taxRate ? (subtotal * taxRate.rate) / 100 : 0;
                        return (subtotal + tax).toFixed(2);
                    })()}
                </span>
             </div>
          </div>

          <div className="flex justify-end pt-4">
            <Button type="submit" disabled={isProcessing}>
                {isProcessing ? t('processing') : t('billing_modal_create_generate_button')}
            </Button>
          </div>
        </form>
      </Modal>

      {/* Advanced Payment Modal */}
      <Modal isOpen={isPaymentModalOpen} onClose={() => setIsPaymentModalOpen(false)} title={t('billing_modal_payment_title')}>
        {payingBill && (
          <form onSubmit={handlePaymentSubmit} className="space-y-6">
            <div className="text-center p-4 bg-slate-50 dark:bg-slate-900 rounded-xl">
              <p className="text-sm text-slate-500 dark:text-slate-400">{t('billing_modal_payment_balance_due')}</p>
              <p className="text-4xl font-bold text-slate-900 dark:text-white">${(payingBill.totalAmount - payingBill.paidAmount).toLocaleString()}</p>
            </div>

            <Select 
              label={t('billing_modal_payment_method')}
              value={paymentForm.method}
              onChange={e => setPaymentForm({...paymentForm, method: e.target.value})}
              required
            >
              <option value="Cash">Cash</option>
              <option value="Insurance">Insurance</option>
              {paymentMethods.filter(p => p.isActive).map(p => <option key={p.id} value={p.name_en}>{language === 'ar' ? p.name_ar : p.name_en}</option>)}
            </Select>

            {/* Dynamic Fields based on Method */}
            <div className="space-y-4 animate-in fade-in">
                {/* 1. Cash or Generic */}
                <Input 
                    label={t('billing_modal_payment_amount')}
                    type="number" 
                    value={paymentForm.amount}
                    onChange={e => setPaymentForm({...paymentForm, amount: e.target.value})}
                    required
                />

                {/* 2. Insurance Specifics */}
                {paymentForm.method === 'Insurance' && (
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4 p-4 bg-blue-50 dark:bg-blue-900/20 rounded-xl border border-blue-100 dark:border-blue-800">
                        <div className="md:col-span-2">
                            <Select 
                                label={t('patients_modal_form_insurance_provider')} 
                                value={paymentForm.insuranceProvider} 
                                onChange={e => setPaymentForm({...paymentForm, insuranceProvider: e.target.value})}
                                required
                            >
                                <option value="">Select Provider...</option>
                                {insuranceProviders.map(p => <option key={p.id} value={p.name_en}>{language === 'ar' ? p.name_ar : p.name_en}</option>)}
                            </Select>
                        </div>
                        <Input 
                            label={t('patients_modal_form_insurance_policy')} 
                            value={paymentForm.policyNumber} 
                            onChange={e => setPaymentForm({...paymentForm, policyNumber: e.target.value})} 
                            required 
                        />
                        <Input 
                            label={t('patients_modal_form_insurance_expiry')} 
                            type="date" 
                            value={paymentForm.expiryDate} 
                            onChange={e => setPaymentForm({...paymentForm, expiryDate: e.target.value})} 
                            required 
                        />
                        <div className="md:col-span-2">
                            <Textarea 
                                label="Coverage Notes" 
                                rows={2} 
                                value={paymentForm.notes} 
                                onChange={e => setPaymentForm({...paymentForm, notes: e.target.value})} 
                            />
                        </div>
                    </div>
                )}

                {/* 3. Bank/Card/Other Specifics */}
                {paymentForm.method !== 'Cash' && paymentForm.method !== 'Insurance' && (
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4 p-4 bg-slate-50 dark:bg-slate-900 rounded-xl border border-slate-200 dark:border-slate-700">
                        <Input 
                            label="Transaction ID / Ref" 
                            value={paymentForm.transactionId} 
                            onChange={e => setPaymentForm({...paymentForm, transactionId: e.target.value})} 
                            required 
                        />
                        <Input 
                            label={t('date')} 
                            type="date" 
                            value={paymentForm.date} 
                            onChange={e => setPaymentForm({...paymentForm, date: e.target.value})} 
                            required 
                        />
                        <div className="md:col-span-2">
                            <Textarea 
                                label={t('patients_modal_action_notes')} 
                                rows={2} 
                                value={paymentForm.notes} 
                                onChange={e => setPaymentForm({...paymentForm, notes: e.target.value})} 
                            />
                        </div>
                    </div>
                )}
            </div>

            <div className="flex justify-end pt-4">
              <Button type="submit" icon={isProcessing ? undefined : CheckCircle} disabled={isProcessing}>
                  {isProcessing ? t('processing') : t('billing_modal_payment_confirm_button')}
              </Button>
            </div>
          </form>
        )}
      </Modal>

      {/* Refund Modal */}
      <Modal isOpen={isRefundModalOpen} onClose={() => setIsRefundModalOpen(false)} title="Process Refund">
        {refundingBill && (
            <form onSubmit={handleRefundSubmit} className="space-y-4">
                <div className="bg-red-50 dark:bg-red-900/20 p-4 rounded-xl border border-red-100 dark:border-red-900/50">
                    <div className="flex items-center gap-3 mb-2">
                        <RefreshCcw className="text-red-600" size={20}/>
                        <p className="text-sm text-red-800 dark:text-red-300 font-bold">Refund for Bill #{refundingBill.billNumber}</p>
                    </div>
                    <div className="flex justify-between text-xs text-red-600 dark:text-red-400">
                        <span>Total Paid: ${refundingBill.paidAmount}</span>
                        <span>Max Refundable: ${refundingBill.paidAmount}</span>
                    </div>
                </div>

                <div className="grid grid-cols-2 gap-4">
                    <Input 
                        label="Refund Amount" 
                        type="number" 
                        max={refundingBill.paidAmount}
                        value={refundForm.amount}
                        onChange={e => setRefundForm({...refundForm, amount: e.target.value})}
                        required
                    />
                    <Select 
                        label="Refund Method"
                        value={refundForm.method}
                        onChange={e => setRefundForm({...refundForm, method: e.target.value})}
                    >
                        <option value="Cash">Cash</option>
                        <option value="Bank Transfer">Bank Transfer</option>
                        <option value="Credit Card Reversal">Credit Card Reversal</option>
                        <option value="Check">Check</option>
                    </Select>
                </div>

                <Select 
                    label="Reason for Refund" 
                    value={refundForm.reason}
                    onChange={e => setRefundForm({...refundForm, reason: e.target.value})}
                    required
                >
                    <option value="Service Cancelled">Service Cancelled</option>
                    <option value="Overcharged">Overcharged / Billing Error</option>
                    <option value="Duplicate Payment">Duplicate Payment</option>
                    <option value="Customer Satisfaction">Customer Satisfaction</option>
                    <option value="Other">Other</option>
                </Select>

                {refundForm.reason === 'Other' && (
                    <Textarea 
                        label="Specify Reason" 
                        value={refundForm.customReason}
                        onChange={e => setRefundForm({...refundForm, customReason: e.target.value})}
                        required
                        rows={2}
                    />
                )}

                <div className="flex justify-end pt-4 gap-2">
                    <Button type="button" variant="secondary" onClick={() => setIsRefundModalOpen(false)}>{t('cancel')}</Button>
                    <Button type="submit" variant="danger" disabled={isProcessing}>
                        {isProcessing ? t('processing') : 'Confirm Refund'}
                    </Button>
                </div>
            </form>
        )}
      </Modal>

      {/* Expense Modal */}
      <Modal isOpen={isExpenseModalOpen} onClose={() => setIsExpenseModalOpen(false)} title="Record Expense">
          <form onSubmit={handleExpenseSubmit} className="space-y-4">
              <Select label="Category" value={expenseForm.category} onChange={e => setExpenseForm({...expenseForm, category: e.target.value})}>
                  <option value="General">General</option>
                  <option value="Supplies">Medical Supplies</option>
                  <option value="Maintenance">Maintenance</option>
                  <option value="Utilities">Utilities</option>
                  <option value="Salary">Salary / Wages</option>
                  <option value="Equipment">Equipment</option>
              </Select>
              <Input label="Amount ($)" type="number" required value={expenseForm.amount} onChange={e => setExpenseForm({...expenseForm, amount: e.target.value})} />
              <div className="grid grid-cols-2 gap-4">
                  <Select label="Payment Method" value={expenseForm.method} onChange={e => setExpenseForm({...expenseForm, method: e.target.value})}>
                      <option value="Cash">Cash</option>
                      <option value="Bank Transfer">Bank Transfer</option>
                      <option value="Check">Check</option>
                  </Select>
                  <Input label="Date" type="date" required value={expenseForm.date} onChange={e => setExpenseForm({...expenseForm, date: e.target.value})} />
              </div>
              <Textarea label="Description" required rows={3} value={expenseForm.description} onChange={e => setExpenseForm({...expenseForm, description: e.target.value})} />
              <div className="flex justify-end pt-4 gap-3">
                  <Button type="button" variant="secondary" onClick={() => setIsExpenseModalOpen(false)}>Cancel</Button>
                  <Button type="submit" disabled={isProcessing}>
                      {isProcessing ? t('processing') : 'Save Expense'}
                  </Button>
              </div>
          </form>
      </Modal>

      <Modal isOpen={!!selectedBill} onClose={() => setSelectedBill(null)} title={t('billing_modal_preview_title')}>
        {selectedBill && (
          <div>
            <InvoiceView bill={selectedBill} />
            <div className="mt-6 flex justify-end gap-3">
              <Button variant="secondary" onClick={() => setSelectedBill(null)}>{t('close')}</Button>
              <Button icon={Printer}>{t('billing_modal_preview_print_button')}</Button>
            </div>
          </div>
        )}
      </Modal>

    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Card, Button, Input, Select, Modal, Badge, Textarea, ConfirmationDialog } from '../components/UI';
import { 
  Wrench, Settings as SettingsIcon, Building, Database, Trash2, Plus, Save, Edit, 
  Bed, Users, Loader2, CheckCircle, XCircle, AlertTriangle, Upload, Download, Server, 
  CreditCard, RotateCcw, Shield, Lock, Activity, RefreshCw, Briefcase, FlaskConical, Stethoscope 
} from 'lucide-react';
import { api } from '../services/api';
import { LabTestCatalog, NurseServiceCatalog, OperationCatalog, Bed as BedType, User, Role, TaxRate, PaymentMethod, InsuranceProvider } from '@/types';
import { Permissions } from '../utils/rbac';
import { useTranslation } from '../context/TranslationContext';

type CatalogType = 'dept' | 'spec' | 'lab' | 'nurse' | 'ops' | 'insurance' | 'banks';

const permissionGroups: Record<string, string[]> = {
  'General': ['VIEW_DASHBOARD'],
  'Patients': ['VIEW_PATIENTS', 'MANAGE_PATIENTS', 'DELETE_PATIENTS'],
  'Appointments': ['VIEW_APPOINTMENTS', 'MANAGE_APPOINTMENTS', 'DELETE_APPOINTMENTS'],
  'Billing': ['VIEW_BILLING', 'MANAGE_BILLING', 'DELETE_BILLING'],
  'HR': ['VIEW_HR', 'MANAGE_HR', 'DELETE_HR'],
  'Admissions': ['VIEW_ADMISSIONS', 'MANAGE_ADMISSIONS', 'DELETE_ADMISSIONS'],
  'Laboratory': ['VIEW_LABORATORY', 'MANAGE_LABORATORY', 'DELETE_LABORATORY'],
  'Operations': ['VIEW_OPERATIONS', 'MANAGE_OPERATIONS', 'DELETE_OPERATIONS'],
  'Reports & Records': ['VIEW_REPORTS', 'MANAGE_REPORTS', 'VIEW_RECORDS'],
  'System': ['VIEW_SETTINGS', 'MANAGE_SETTINGS', 'MANAGE_CONFIGURATION'],
};

const DiagnosticStat = ({ title, value, icon: Icon }: any) => (
  <div className="bg-slate-50 dark:bg-slate-900 p-4 rounded-xl border border-slate-200 dark:border-slate-700 flex items-center gap-4">
    <div className="p-3 bg-white dark:bg-slate-800 rounded-lg shadow-sm text-primary-600">
       <Icon size={20} />
    </div>
    <div>
      <p className="text-xs text-slate-500 font-medium uppercase tracking-wider">{title}</p>
      <p className="text-lg font-bold text-slate-800 dark:text-white">{value}</p>
    </div>
  </div>
);

export const Configuration = () => {
  const { t } = useTranslation();
  const [activeTab, setActiveTab] = useState<'general' | 'beds' | 'catalogs' | 'users' | 'data' | 'financial' | 'diagnostics'>('general');
  const [loading, setLoading] = useState(true);

  const [processStatus, setProcessStatus] = useState<'idle' | 'processing' | 'success' | 'error'>('idle');
  const [processMessage, setProcessMessage] = useState('');

  const [confirmState, setConfirmState] = useState<{
    isOpen: boolean;
    title: string;
    message: string;
    action: () => void;
    type?: 'danger' | 'warning';
  }>({ isOpen: false, title: '', message: '', action: () => {} });

  // Data States
  const [settings, setSettings] = useState({ hospitalName: '', hospitalAddress: '', hospitalPhone: '', currency: '$' });
  const [healthData, setHealthData] = useState<any>(null);
  const [testLogs, setTestLogs] = useState<string[]>([]);
  const [isTesting, setIsTesting] = useState(false);
  const [users, setUsers] = useState<any[]>([]);
  const [rolePermissions, setRolePermissions] = useState<Record<string, string[]>>({});
  const [beds, setBeds] = useState<BedType[]>([]);
  const [departments, setDepartments] = useState<any[]>([]);
  const [specializations, setSpecializations] = useState<any[]>([]);
  const [labTests, setLabTests] = useState<LabTestCatalog[]>([]);
  const [nurseServices, setNurseServices] = useState<NurseServiceCatalog[]>([]);
  const [operations, setOperations] = useState<OperationCatalog[]>([]);
  const [insuranceProviders, setInsuranceProviders] = useState<InsuranceProvider[]>([]);
  const [banks, setBanks] = useState<any[]>([]);
  const [taxes, setTaxes] = useState<TaxRate[]>([]);
  const [paymentMethods, setPaymentMethods] = useState<PaymentMethod[]>([]);
  const [restoreFile, setRestoreFile] = useState<File | null>(null);

  // Modal & Form States
  const [isUserModalOpen, setIsUserModalOpen] = useState(false);
  const [userForm, setUserForm] = useState<any>({});
  const [editingUserId, setEditingUserId] = useState<number | null>(null);
  const [userTabMode, setUserTabMode] = useState<'accounts' | 'roles'>('accounts');
  const [availableRoles] = useState<string[]>(['admin', 'manager', 'receptionist', 'technician', 'accountant', 'doctor', 'nurse', 'pharmacist', 'hr']);
  const [isBedModalOpen, setIsBedModalOpen] = useState(false);
  const [bedForm, setBedForm] = useState<Partial<BedType>>({});
  const [editingBedId, setEditingBedId] = useState<number | null>(null);
  const [catalogTab, setCatalogTab] = useState<CatalogType>('lab');
  const [isItemModalOpen, setIsItemModalOpen] = useState(false);
  const [itemFormData, setItemFormData] = useState<any>({});
  const [editingItemId, setEditingItemId] = useState<number | null>(null);
  const [financeForm, setFinanceForm] = useState<any>({});
  const [editingFinanceId, setEditingFinanceId] = useState<number | null>(null);
  const [financeTab, setFinanceTab] = useState<'tax' | 'payment'>('tax');
  const [isFinanceModalOpen, setIsFinanceModalOpen] = useState(false);


  const loadAllData = async (silent = false) => {
    if (!silent) setLoading(true);
    try {
      const [s, d, sp, b, l, n, o, ip, bn, u, t, p, rPerms] = await Promise.all([
        api.getSystemSettings(),
        api.getDepartments(),
        api.getSpecializations(),
        api.getConfigBeds(),
        api.getLabTests(),
        api.getNurseServices(),
        api.getOperations(),
        api.getInsuranceProviders(),
        api.getBanks(),
        api.getSystemUsers(),
        api.getTaxRates(),
        api.getPaymentMethods(),
        api.getRolePermissions()
      ]);
      if (s) setSettings(s);
      setDepartments(Array.isArray(d) ? d : []);
      setSpecializations(Array.isArray(sp) ? sp : []);
      setBeds(Array.isArray(b) ? b : []);
      setLabTests(Array.isArray(l) ? l : []);
      setNurseServices(Array.isArray(n) ? n : []);
      setOperations(Array.isArray(o) ? o : []);
      setInsuranceProviders(Array.isArray(ip) ? ip : []);
      setBanks(Array.isArray(bn) ? bn : []);
      setUsers(Array.isArray(u) ? u : []);
      setTaxes(Array.isArray(t) ? t : []);
      setPaymentMethods(Array.isArray(p) ? p : []);
      setRolePermissions(rPerms || {});
    } catch (e) {
      console.error("Failed to load config data", e);
    } finally {
      if (!silent) setLoading(false);
    }
  };

  useEffect(() => { loadAllData(); }, []);

  const handleAction = async (action: () => Promise<void>, successMsg: string) => {
    setProcessStatus('processing');
    setProcessMessage(t('processing'));
    try {
      await action();
      setProcessStatus('success');
      setProcessMessage(successMsg);
      await loadAllData(true);
      setTimeout(() => { setProcessStatus('idle'); }, 1500);
    } catch (e: any) {
      setProcessStatus('error');
      setProcessMessage(e.response?.data?.error || e.message || 'An error occurred');
    }
  };

  // --- Handlers for each section ---

  const handleSaveSettings = (e: React.FormEvent) => {
    e.preventDefault();
    handleAction(async () => {
      await api.updateSystemSettings(settings);
      if (settings.hospitalName) localStorage.setItem('hospital_name', settings.hospitalName);
    }, 'Settings saved successfully');
  };

  // User Handlers
  const openUserModal = (user?: any) => {
    setEditingUserId(user ? user.id : null);
    setUserForm(user ? { ...user, password: '' } : { username: '', fullName: '', role: 'manager', isActive: true });
    setIsUserModalOpen(true);
  };
  const handleUserSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    handleAction(async () => {
      if (editingUserId) await api.updateSystemUser(editingUserId, userForm);
      else await api.addSystemUser(userForm);
      setIsUserModalOpen(false);
    }, editingUserId ? 'User updated' : 'User created');
  };
  const handleDeleteUser = (id: number) => {
    setConfirmState({
      isOpen: true, title: 'Delete User', message: 'Are you sure? This will remove the user permanently.',
      action: () => handleAction(async () => await api.deleteSystemUser(id), 'User deleted')
    });
  };
  const togglePermission = (role: string, permission: string) => {
    if (role === 'admin') return;
    const currentPerms = rolePermissions[role] || [];
    const updatedPerms = currentPerms.includes(permission) ? currentPerms.filter(p => p !== permission) : [...currentPerms, permission];
    setRolePermissions(prev => ({ ...prev, [role]: updatedPerms }));
  };
  const savePermissions = (role: string) => {
    handleAction(async () => await api.updateRolePermissions(role, rolePermissions[role] || []), `Permissions updated for ${role}`);
  };

  // Bed Handlers
  const openBedModal = (bed?: BedType) => {
    setEditingBedId(bed ? bed.id : null);
    setBedForm(bed ? { ...bed } : { type: 'General', status: 'available', costPerDay: 0 });
    setIsBedModalOpen(true);
  };
  const handleBedSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    handleAction(async () => {
      if (editingBedId) await api.updateBed(editingBedId, bedForm);
      else await api.addBed(bedForm);
      setIsBedModalOpen(false);
    }, editingBedId ? 'Room updated' : 'Room added');
  };
  const handleDeleteBed = (id: number) => {
    setConfirmState({
      isOpen: true, title: 'Delete Room', message: 'Are you sure?',
      action: () => handleAction(async () => await api.deleteBed(id), 'Room deleted')
    });
  };

  // Catalog Handlers
  const openItemModal = (item?: any) => {
    setEditingItemId(item ? item.id : null);
    setItemFormData(item ? { ...item } : {});
    setIsItemModalOpen(true);
  };
  const handleItemSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const { apiAdd, apiUpdate } = catalogMetadata[catalogTab];
    handleAction(async () => {
      if (editingItemId) await apiUpdate(editingItemId, itemFormData);
      else await apiAdd(itemFormData);
      setIsItemModalOpen(false);
    }, editingItemId ? 'Item updated' : 'Item added');
  };
  const handleDeleteItem = (id: number) => {
    const { apiDelete } = catalogMetadata[catalogTab];
    setConfirmState({
      isOpen: true, title: 'Delete Item', message: 'This will be permanently removed.',
      action: () => handleAction(async () => await apiDelete(id), 'Item deleted')
    });
  };

  // Financial Handlers
  const openFinanceModal = (type: 'tax' | 'payment', item?: any) => {
    setFinanceTab(type);
    setEditingFinanceId(item ? item.id : null);
    setFinanceForm(item ? { ...item } : { name_en: '', name_ar: '', isActive: true });
    setIsFinanceModalOpen(true);
  };
  const handleFinanceSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    handleAction(async () => {
      if (financeTab === 'tax') {
        if (editingFinanceId) await api.updateTaxRate(editingFinanceId, financeForm);
        else await api.addTaxRate(financeForm);
      } else {
        if (editingFinanceId) await api.updatePaymentMethod(editingFinanceId, financeForm);
        else await api.addPaymentMethod(financeForm);
      }
      setIsFinanceModalOpen(false);
    }, editingFinanceId ? 'Updated' : 'Created');
  };
  const handleDeleteFinance = (id: number, type: 'tax' | 'payment') => {
    setConfirmState({
      isOpen: true, title: 'Delete Item', message: 'Are you sure?',
      action: () => handleAction(async () => {
        if (type === 'tax') await api.deleteTaxRate(id);
        else await api.deletePaymentMethod(id);
      }, 'Deleted')
    });
  };

  // Data Management Handlers
  const handleDownloadBackup = () => api.downloadBackup();
  const handleRestoreDatabase = (e: React.FormEvent) => {
    e.preventDefault();
    if (!restoreFile) return;
    setConfirmState({
      isOpen: true, title: 'Overwrite Database', message: 'This will completely OVERWRITE the current database. All recent data will be lost. Are you sure?', type: 'danger',
      action: () => handleAction(async () => {
        await api.restoreDatabase(restoreFile);
        setTimeout(() => window.location.reload(), 1500);
      }, 'Database restored. Reloading...')
    });
  };
  const handleResetDatabase = () => {
    setConfirmState({
      isOpen: true, title: 'Factory Reset', message: 'DANGER: This will wipe ALL data and reset the system to its initial state. This action CANNOT be undone.', type: 'danger',
      action: () => handleAction(async () => {
          await api.resetDatabase();
          setTimeout(() => window.location.reload(), 2000);
      }, 'Database reset. Reloading...')
    });
  };

  // Diagnostics
  const runDiagnostics = async () => {
    setIsTesting(true);
    setTestLogs(['Starting diagnostics...']);
    try {
      const addLog = (msg: string) => setTestLogs(prev => [...prev, msg]);
      await new Promise(res => setTimeout(res, 300));

      addLog('Checking API server connectivity...');
      const health = await api.checkSystemHealth();
      setHealthData(health);
      addLog(`✅ Server operational. Uptime: ${(health.uptime / 60).toFixed(1)} mins.`);

      await new Promise(res => setTimeout(res, 500));
      addLog('Verifying database connection...');
      addLog(`✅ Database connected. Latency: ${health.database.latency}.`);

      await new Promise(res => setTimeout(res, 300));
      addLog('All tests passed.');
    } catch (e: any) {
      setTestLogs(prev => [...prev, `❌ Test failed: ${e.message}`]);
      setHealthData({ status: 'error' });
    } finally {
      setIsTesting(false);
    }
  };

  // --- DYNAMIC CATALOG CONFIGURATION ---
  const catalogMetadata: Record<CatalogType, any> = {
    dept: {
      label: 'Departments',
      data: departments,
      fields: [
        { name: 'name_en', label: 'Name (EN)', type: 'text', required: true },
        { name: 'name_ar', label: 'Name (AR)', type: 'text', required: true },
        { name: 'description_en', label: 'Description (EN)', type: 'textarea' },
        { name: 'description_ar', label: 'Description (AR)', type: 'textarea' },
      ],
      apiAdd: api.addDepartment, apiUpdate: api.updateDepartment, apiDelete: api.deleteDepartment
    },
    spec: {
      label: 'Specializations',
      data: specializations,
      fields: [
        { name: 'name_en', label: 'Name (EN)', type: 'text', required: true },
        { name: 'name_ar', label: 'Name (AR)', type: 'text', required: true },
        { name: 'related_role', label: 'Related Role', type: 'select', options: availableRoles },
        { name: 'description_en', label: 'Description (EN)', type: 'textarea' },
        { name: 'description_ar', label: 'Description (AR)', type: 'textarea' },
      ],
      apiAdd: api.addSpecialization, apiUpdate: api.updateSpecialization, apiDelete: api.deleteSpecialization
    },
    lab: {
      label: 'Lab Tests',
      data: labTests,
      fields: [
        { name: 'name_en', label: 'Name (EN)', type: 'text', required: true },
        { name: 'name_ar', label: 'Name (AR)', type: 'text', required: true },
        { name: 'category_en', label: 'Category (EN)', type: 'text' },
        { name: 'category_ar', label: 'Category (AR)', type: 'text' },
        { name: 'cost', label: 'Cost', type: 'number', prefix: '$' },
        { name: 'normal_range', label: 'Normal Range', type: 'text' },
      ],
      apiAdd: api.addLabTest, apiUpdate: api.updateLabTest, apiDelete: api.deleteLabTest
    },
    nurse: {
      label: 'Nurse Services',
      data: nurseServices,
      fields: [
        { name: 'name_en', label: 'Name (EN)', type: 'text', required: true },
        { name: 'name_ar', label: 'Name (AR)', type: 'text', required: true },
        { name: 'description_en', label: 'Description (EN)', type: 'textarea' },
        { name: 'description_ar', label: 'Description (AR)', type: 'textarea' },
        { name: 'cost', label: 'Cost', type: 'number', prefix: '$' },
      ],
      apiAdd: api.addNurseService, apiUpdate: api.updateNurseService, apiDelete: api.deleteNurseService
    },
    ops: {
      label: 'Operations',
      data: operations,
      fields: [
        { name: 'name_en', label: 'Name (EN)', type: 'text', required: true },
        { name: 'name_ar', label: 'Name (AR)', type: 'text', required: true },
        { name: 'base_cost', label: 'Base Cost', type: 'number', prefix: '$' },
      ],
      apiAdd: api.addOperationCatalog, apiUpdate: api.updateOperationCatalog, apiDelete: api.deleteOperationCatalog
    },
    insurance: {
      label: 'Insurance',
      data: insuranceProviders,
      fields: [
        { name: 'name_en', label: 'Name (EN)', type: 'text', required: true },
        { name: 'name_ar', label: 'Name (AR)', type: 'text', required: true },
        { name: 'is_active', label: 'Status', type: 'toggle' },
      ],
      apiAdd: api.addInsuranceProvider, apiUpdate: api.updateInsuranceProvider, apiDelete: api.deleteInsuranceProvider
    },
    banks: {
      label: 'Banks',
      data: banks,
      fields: [
        { name: 'name_en', label: 'Name (EN)', type: 'text', required: true },
        { name: 'name_ar', label: 'Name (AR)', type: 'text', required: true },
        { name: 'is_active', label: 'Status', type: 'toggle' },
      ],
      apiAdd: api.addBank, apiUpdate: api.updateBank, apiDelete: api.deleteBank
    }
  };

  const formatPermissionName = (p: string) => {
    return p.replace(/_/g, ' ').toLowerCase();
  };


  return (
    <div className="space-y-6">
      <h1 className="text-2xl font-bold text-gray-900 dark:text-white">{t('config_title')}</h1>

      <div className="flex border-b border-gray-200 dark:border-slate-700 bg-white dark:bg-slate-800 rounded-t-xl px-4 pt-2 overflow-x-auto">
        {[
          { id: 'general', icon: SettingsIcon, label: t('config_tab_general') },
          { id: 'users', icon: Shield, label: t('config_tab_roles') }, 
          { id: 'financial', icon: CreditCard, label: t('config_tab_financial') },
          { id: 'beds', icon: Bed, label: t('config_tab_beds') },
          { id: 'catalogs', icon: Database, label: t('config_tab_catalogs') },
          { id: 'data', icon: Server, label: t('config_tab_data') },
          { id: 'diagnostics', icon: Activity, label: t('config_tab_health') }
        ].map(tab => (
          <button 
            key={tab.id}
            onClick={() => setActiveTab(tab.id as any)} 
            className={`px-5 py-3 font-medium text-sm border-b-2 transition-all flex items-center gap-2 whitespace-nowrap 
              ${activeTab === tab.id 
                ? 'border-primary-600 text-primary-600 bg-primary-50/50 dark:bg-primary-900/20' 
                : 'border-transparent text-gray-500 dark:text-slate-400 hover:text-gray-700 dark:hover:text-slate-200 hover:bg-gray-50 dark:hover:bg-slate-700'}`}
          >
            <tab.icon size={18}/> {tab.label}
          </button>
        ))}
      </div>

      <div className="bg-white dark:bg-slate-800 rounded-b-xl shadow-sm border border-t-0 border-gray-200 dark:border-slate-700 p-6 min-h-[400px] relative">
        {loading && <div className="absolute inset-0 z-10 bg-white/80 dark:bg-slate-800/80 flex items-center justify-center"><Loader2 className="w-8 h-8 animate-spin text-primary-500" /></div>}

        {!loading && (
          <>
            {activeTab === 'general' && (
              <form onSubmit={handleSaveSettings} className="max-w-xl space-y-6 animate-in fade-in">
                <Input label={t('config_general_hospital_name')} value={settings.hospitalName} onChange={e => setSettings({...settings, hospitalName: e.target.value})} />
                <Input label={t('config_general_address')} value={settings.hospitalAddress} onChange={e => setSettings({...settings, hospitalAddress: e.target.value})} />
                <div className="pt-4 border-t dark:border-slate-700">
                  <Button type="submit" icon={Save}>{t('config_general_save_button')}</Button>
                </div>
              </form>
            )}

            {activeTab === 'users' && (
              <div className="animate-in fade-in">
                <div className="flex gap-2 mb-6">
                   <Button variant={userTabMode === 'accounts' ? 'primary' : 'outline'} onClick={() => setUserTabMode('accounts')} icon={Users}>{t('config_users_accounts_tab')}</Button>
                   <Button variant={userTabMode === 'roles' ? 'primary' : 'outline'} onClick={() => setUserTabMode('roles')} icon={Lock}>{t('config_users_roles_tab')}</Button>
                </div>

                {userTabMode === 'accounts' ? (
                  <>
                    <div className="flex justify-end mb-4"><Button icon={Plus} onClick={() => openUserModal()}>{t('config_users_add_button')}</Button></div>
                    <div className="overflow-x-auto border rounded-xl shadow-sm">
                      <table className="min-w-full divide-y">
                        <thead className="bg-slate-50 dark:bg-slate-900">
                          <tr>
                            <th className="px-4 py-3 text-left text-xs font-bold text-gray-500 uppercase">{t('config_users_header_user')}</th>
                            <th className="px-4 py-3 text-left text-xs font-bold text-gray-500 uppercase">{t('config_users_header_role')}</th>
                            <th className="px-4 py-3 text-center text-xs font-bold text-gray-500 uppercase">{t('config_users_header_status')}</th>
                            <th className="px-4 py-3"></th>
                          </tr>
                        </thead>
                        <tbody className="bg-white divide-y dark:bg-slate-800">
                          {users.map(user => (
                            <tr key={user.id}>
                              <td className="px-4 py-3"><div className="font-medium">{user.fullName}</div><div className="text-xs text-slate-500">{user.username}</div></td>
                              <td className="px-4 py-3 capitalize"><Badge color="blue">{user.role}</Badge></td>
                              <td className="px-4 py-3 text-center"><Badge color={user.isActive ? 'green' : 'gray'}>{user.isActive ? 'Active' : 'Inactive'}</Badge></td>
                              <td className="px-4 py-3 text-right">
                                <button onClick={() => openUserModal(user)} className="p-1 text-slate-400 hover:text-primary-600"><Edit size={16}/></button>
                                <button onClick={() => handleDeleteUser(user.id)} className="p-1 text-slate-400 hover:text-red-600"><Trash2 size={16}/></button>
                              </td>
                            </tr>
                          ))}
                        </tbody>
                      </table>
                    </div>
                  </>
                ) : (
                  <div className="overflow-x-auto border border-slate-200 dark:border-slate-700 rounded-xl shadow-sm">
                    <table className="min-w-full divide-y divide-slate-200 dark:divide-slate-700">
                      <thead className="bg-slate-50 dark:bg-slate-900 sticky top-0 z-10">
                        <tr>
                          <th className="px-4 py-3 text-left text-xs font-bold text-gray-500 uppercase tracking-wider w-1/4">
                            Feature
                          </th>
                          {availableRoles.map(role => (
                            <th key={role} className="px-4 py-3 text-center text-xs font-bold text-gray-500 uppercase tracking-wider">
                              <div className="flex flex-col items-center gap-2">
                                <span className="capitalize">{role}</span>
                                {role !== 'admin' && (
                                  <Button size="sm" onClick={() => savePermissions(role)} className="!px-2 !py-0.5 !text-[10px] h-auto">
                                    {t('config_users_permissions_save_button')}
                                  </Button>
                                )}
                              </div>
                            </th>
                          ))}
                        </tr>
                      </thead>
                      <tbody className="bg-white dark:bg-slate-800">
                        {Object.entries(permissionGroups).map(([groupName, perms]) => (
                          <React.Fragment key={groupName}>
                            <tr className="bg-slate-50/50 dark:bg-slate-900/50">
                              <td colSpan={availableRoles.length + 1} className="px-4 py-2 text-sm font-bold text-slate-600 dark:text-slate-300">
                                {groupName}
                              </td>
                            </tr>
                            {perms.map(p => (
                              <tr key={p} className="hover:bg-slate-50 dark:hover:bg-slate-700/30">
                                <td className="px-4 py-3 text-sm font-medium text-slate-700 dark:text-slate-300 capitalize">
                                  {formatPermissionName(p)}
                                </td>
                                {availableRoles.map(role => (
                                  <td key={`${role}-${p}`} className="px-4 py-3 text-center">
                                    <input
                                      type="checkbox"
                                      className="h-5 w-5 rounded text-primary-600 focus:ring-primary-500 disabled:opacity-50 cursor-pointer disabled:cursor-not-allowed"
                                      checked={(rolePermissions[role] || []).includes(p)}
                                      onChange={() => togglePermission(role, p)}
                                      disabled={role === 'admin'}
                                    />
                                  </td>
                                ))}
                              </tr>
                            ))}
                          </React.Fragment>
                        ))}
                      </tbody>
                    </table>
                  </div>
                )}
              </div>
            )}

            {activeTab === 'financial' && (
              <div className="animate-in fade-in">
                <div className="flex gap-2 mb-6">
                   <Button variant={financeTab === 'tax' ? 'primary' : 'outline'} onClick={() => setFinanceTab('tax')}>{t('config_financial_tax_tab')}</Button>
                   <Button variant={financeTab === 'payment' ? 'primary' : 'outline'} onClick={() => setFinanceTab('payment')}>{t('config_financial_payment_tab')}</Button>
                </div>
                {financeTab === 'tax' ? (
                  <div>
                    <div className="flex justify-end mb-4"><Button size="sm" icon={Plus} onClick={() => openFinanceModal('tax')}>{t('add')}</Button></div>
                    {taxes.map(t => <div key={t.id} className="flex justify-between items-center py-2 border-b last:border-0"><span>{t.name_en} ({t.rate}%)</span><div><button onClick={() => openFinanceModal('tax', t)} className="p-1"><Edit size={14}/></button><button onClick={() => handleDeleteFinance(t.id, 'tax')} className="p-1 text-red-500"><Trash2 size={14}/></button></div></div>)}
                  </div>
                ) : (
                  <div>
                    <div className="flex justify-end mb-4"><Button size="sm" icon={Plus} onClick={() => openFinanceModal('payment')}>{t('add')}</Button></div>
                    {paymentMethods.map(p => <div key={p.id} className="flex justify-between items-center py-2 border-b last:border-0"><span>{p.name_en}</span><div><button onClick={() => openFinanceModal('payment', p)} className="p-1"><Edit size={14}/></button><button onClick={() => handleDeleteFinance(p.id, 'payment')} className="p-1 text-red-500"><Trash2 size={14}/></button></div></div>)}
                  </div>
                )}
              </div>
            )}

            {activeTab === 'beds' && (
              <div className="animate-in fade-in">
                <div className="flex justify-end mb-4"><Button icon={Plus} onClick={() => openBedModal()}>{t('config_beds_add_button')}</Button></div>
                <div className="overflow-x-auto border rounded-xl shadow-sm">
                  <table className="min-w-full divide-y">
                    <thead className="bg-slate-50 dark:bg-slate-900">
                      <tr>
                        <th className="px-4 py-3 text-left text-xs font-bold text-gray-500 uppercase">{t('config_beds_header_room')}</th>
                        <th className="px-4 py-3 text-left text-xs font-bold text-gray-500 uppercase">{t('config_beds_header_type')}</th>
                        <th className="px-4 py-3 text-right text-xs font-bold text-gray-500 uppercase">{t('config_beds_header_cost')}</th>
                        <th className="px-4 py-3 text-center text-xs font-bold text-gray-500 uppercase">{t('config_beds_header_status')}</th>
                        <th className="px-4 py-3"></th>
                      </tr>
                    </thead>
                    <tbody className="bg-white divide-y dark:bg-slate-800">
                      {beds.map(bed => (
                        <tr key={bed.id}>
                          <td className="px-4 py-3 font-medium">{bed.roomNumber}</td>
                          <td className="px-4 py-3">{bed.type}</td>
                          <td className="px-4 py-3 text-right font-mono">${bed.costPerDay}</td>
                          <td className="px-4 py-3 text-center capitalize"><Badge color={bed.status === 'available' ? 'green' : bed.status === 'cleaning' ? 'purple' : 'red'}>{bed.status}</Badge></td>
                          <td className="px-4 py-3 text-right">
                            <button onClick={() => openBedModal(bed)} className="p-1 text-slate-400 hover:text-primary-600"><Edit size={16}/></button>
                            <button onClick={() => handleDeleteBed(bed.id)} className="p-1 text-slate-400 hover:text-red-600"><Trash2 size={16}/></button>
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              </div>
            )}

            {activeTab === 'catalogs' && (
              <div className="animate-in fade-in">
                <div className="flex flex-col sm:flex-row justify-between gap-4 mb-6">
                  <div className="flex gap-1 bg-gray-100 dark:bg-slate-900 p-1 rounded-xl w-full sm:w-auto overflow-x-auto">
                    {Object.keys(catalogMetadata).map(key => (
                      <button 
                        key={key}
                        onClick={() => setCatalogTab(key as CatalogType)} 
                        className={`px-4 py-2 rounded-lg text-sm font-medium transition-all shadow-sm whitespace-nowrap ${catalogTab === key ? 'bg-white dark:bg-slate-800 text-primary-700 shadow' : 'bg-transparent text-gray-500 hover:text-gray-700'}`}
                      >
                        {catalogMetadata[key as CatalogType].label}
                      </button>
                    ))}
                  </div>
                  <Button size="sm" icon={Plus} onClick={() => openItemModal()}>{t('config_catalogs_add_button')}</Button>
                </div>

                <div className="overflow-x-auto border rounded-xl shadow-sm">
                  <table className="min-w-full divide-y divide-gray-200 dark:divide-slate-700">
                    <thead className="bg-gray-50/80 dark:bg-slate-900">
                      <tr>
                        <th className="px-4 py-3 text-left text-xs font-bold text-gray-500 uppercase">{t('config_catalogs_header_name_en')}</th>
                        <th className="px-4 py-3 text-left text-xs font-bold text-gray-500 uppercase">{t('config_catalogs_header_name_ar')}</th>
                        <th className="px-4 py-3 text-right text-xs font-bold text-gray-500 uppercase">{t('config_catalogs_header_details')}</th>
                        <th className="px-4 py-3 text-right"></th>
                      </tr>
                    </thead>
                    <tbody className="bg-white dark:bg-slate-800 divide-y divide-gray-200 dark:divide-slate-700">
                      {catalogMetadata[catalogTab].data.map((item: any) => (
                        <tr key={item.id} className="hover:bg-slate-50 dark:hover:bg-slate-700">
                          <td className="px-4 py-3 text-sm font-medium text-gray-900">{item.name_en}</td>
                          <td className="px-4 py-3 text-sm text-gray-700 dark:text-slate-300">{item.name_ar}</td>
                          <td className="px-4 py-3 text-sm text-right font-mono text-slate-500">
                            {item.cost !== undefined && `$${item.cost}`}
                            {item.base_cost !== undefined && `$${item.base_cost}`}
                            {item.rate !== undefined && `${item.rate}%`}
                            {item.related_role && <span className="mr-2 text-xs bg-gray-100 dark:bg-gray-700 px-1 rounded">{item.related_role}</span>}
                            {item.isActive !== undefined && <Badge color={item.isActive ? 'green' : 'gray'}>{item.isActive ? 'Active' : 'Inactive'}</Badge>}
                          </td>
                          <td className="px-4 py-3 text-right">
                            <button onClick={() => openItemModal(item)} className="p-1 text-slate-400 hover:text-primary-600"><Edit size={16}/></button>
                            <button onClick={() => handleDeleteItem(item.id)} className="p-1 text-slate-400 hover:text-red-600"><Trash2 size={16}/></button>
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              </div>
            )}

            {activeTab === 'data' && (
              <div className="max-w-xl space-y-8 animate-in fade-in">
                <Card title={t('config_data_backup_title')} action={<Button icon={Download} onClick={handleDownloadBackup}>{t('config_data_backup_button')}</Button>}>
                  <p>{t('config_data_backup_note')}</p>
                </Card>
                <Card title={t('config_data_restore_title')}>
                  <form onSubmit={handleRestoreDatabase} className="space-y-4">
                    <Input type="file" accept=".db,.sqlite,.sqlite3" onChange={e => setRestoreFile(e.target.files ? e.target.files[0] : null)} />
                    <Button type="submit" icon={Upload} disabled={!restoreFile}>{t('config_data_restore_button')}</Button>
                  </form>
                </Card>
                <Card title={t('config_data_danger_title')} className="border-red-500 bg-red-50 dark:bg-red-900/10">
                  <div className="flex justify-between items-center">
                    <div>
                      <h4 className="font-bold text-red-800 dark:text-red-300">{t('config_data_danger_reset_title')}</h4>
                      <p className="text-sm text-red-600 dark:text-red-400">{t('config_data_danger_reset_note')}</p>
                    </div>
                    <Button variant="danger" icon={RotateCcw} onClick={handleResetDatabase}>{t('config_data_danger_reset_button')}</Button>
                  </div>
                </Card>
              </div>
            )}

            {activeTab === 'diagnostics' && (
              <div className="max-w-3xl space-y-6 animate-in fade-in">
                <Button onClick={runDiagnostics} disabled={isTesting} icon={isTesting ? undefined : RefreshCw}>
                  {isTesting ? <><Loader2 className="w-4 h-4 mr-2 animate-spin"/>{t('config_health_running_button')}</> : t('config_health_run_button')}
                </Button>

                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
                  <DiagnosticStat title={t('config_health_stat_status')} value={healthData?.status || 'Unknown'} icon={healthData?.status === 'operational' ? CheckCircle : AlertTriangle} />
                  <DiagnosticStat title={t('config_health_stat_latency')} value={healthData?.database?.latency || 'N/A'} icon={Database} />
                  <DiagnosticStat title={t('config_health_stat_uptime')} value={healthData?.uptime ? `${(healthData.uptime / 60).toFixed(1)} mins` : 'N/A'} icon={Activity} />
                  <DiagnosticStat title={t('config_health_stat_memory')} value={healthData?.memory?.rss || 'N/A'} icon={Server} />
                </div>

                {testLogs.length > 0 && (
                  <div className="bg-slate-900 text-slate-300 p-4 rounded-xl text-xs font-mono h-64 overflow-y-auto custom-scrollbar">
                    {testLogs.map((log, i) => <p key={i} className={`flex items-start gap-2 ${log.startsWith('❌') ? 'text-red-400' : log.startsWith('✅') ? 'text-green-400' : ''}`}><span className="text-slate-600 select-none">&gt;</span><span className="flex-1">{log}</span></p>)}
                  </div>
                )}
              </div>
            )}

          </>
        )}
      </div>

       {/* CATALOG ITEM MODAL (DYNAMIC) */}
      <Modal 
        isOpen={isItemModalOpen} 
        onClose={() => setIsItemModalOpen(false)} 
        title={`${editingItemId ? t('edit') : t('add')} ${catalogMetadata[catalogTab].label}`}
      >
        <form onSubmit={handleItemSubmit} className="space-y-4">
          {catalogMetadata[catalogTab].fields.map((field: any) => {
            if (field.type === 'textarea') {
              return <Textarea key={field.name} label={field.label} value={itemFormData[field.name] || ''} onChange={e => setItemFormData({...itemFormData, [field.name]: e.target.value})} required={field.required} />
            }
            if (field.type === 'select') {
                return (
                    <Select key={field.name} label={field.label} value={itemFormData[field.name] || ''} onChange={e => setItemFormData({...itemFormData, [field.name]: e.target.value})}>
                        <option value="">Select Role...</option>
                        {field.options.map((opt: string) => <option key={opt} value={opt}>{opt.charAt(0).toUpperCase() + opt.slice(1)}</option>)}
                    </Select>
                )
            }
            if (field.type === 'toggle') {
              return (
                <div key={field.name} className="flex items-center gap-2">
                  <input type="checkbox" id={field.name} checked={itemFormData[field.name] !== false} onChange={e => setItemFormData({...itemFormData, [field.name]: e.target.checked})} />
                  <label htmlFor={field.name}>{field.label}</label>
                </div>
              )
            }
            return <Input key={field.name} label={field.label} type={field.type || 'text'} value={itemFormData[field.name] || ''} onChange={e => setItemFormData({...itemFormData, [field.name]: e.target.value})} required={field.required} prefix={field.prefix} />
          })}
          <div className="flex justify-end pt-4 gap-3">
            <Button type="button" variant="secondary" onClick={() => setIsItemModalOpen(false)}>{t('cancel')}</Button>
            <Button type="submit">{editingItemId ? t('edit') : t('add')}</Button>
          </div>
        </form>
      </Modal>

      <Modal isOpen={isUserModalOpen} onClose={() => setIsUserModalOpen(false)} title={editingUserId ? t('edit') : t('add')}>
        <form onSubmit={handleUserSubmit} className="space-y-4">
          <Input label={t('patients_modal_form_fullName')} required value={userForm.fullName || ''} onChange={e => setUserForm({...userForm, fullName: e.target.value})} />
          <Input label={t('settings_profile_username')} required value={userForm.username || ''} onChange={e => setUserForm({...userForm, username: e.target.value})} />
          <Input label={t('login_password_label')} type="password" placeholder={editingUserId ? 'Leave blank to keep unchanged' : ''} value={userForm.password || ''} onChange={e => setUserForm({...userForm, password: e.target.value})} required={!editingUserId} />
          <Input label={t('settings_profile_email')} type="email" value={userForm.email || ''} onChange={e => setUserForm({...userForm, email: e.target.value})} />
          <Select label={t('config_users_header_role')} value={userForm.role} onChange={e => setUserForm({...userForm, role: e.target.value})}>
            {availableRoles.map(r => <option key={r} value={r} className="capitalize">{r}</option>)}
          </Select>
          <div className="flex justify-end pt-4 gap-3">
            <Button type="button" variant="secondary" onClick={() => setIsUserModalOpen(false)}>{t('cancel')}</Button>
            <Button type="submit">{editingUserId ? t('edit') : t('add')}</Button>
          </div>
        </form>
      </Modal>

      <Modal isOpen={isBedModalOpen} onClose={() => setIsBedModalOpen(false)} title={editingBedId ? t('edit') : t('add')}>
         <form onSubmit={handleBedSubmit} className="space-y-4">
           <Input label={t('config_beds_header_room')} required value={bedForm.roomNumber || ''} onChange={e => setBedForm({...bedForm, roomNumber: e.target.value})} />
           <Select label={t('config_beds_header_type')} value={bedForm.type} onChange={e => setBedForm({...bedForm, type: e.target.value as any})}>
             <option>General</option><option>Private</option><option>ICU</option>
           </Select>
           <Input label={t('config_beds_header_cost')} type="number" value={bedForm.costPerDay || 0} onChange={e => setBedForm({...bedForm, costPerDay: parseFloat(e.target.value)})} />
           <Select label={t('status')} value={bedForm.status} onChange={e => setBedForm({...bedForm, status: e.target.value as any})}>
             <option value="available">Available</option>
             <option value="maintenance">Maintenance</option>
             <option value="cleaning">Cleaning</option>
             <option value="reserved">Reserved</option>
             <option value="occupied">Occupied</option>
           </Select>
           <div className="flex justify-end pt-4 gap-3">
             <Button type="button" variant="secondary" onClick={() => setIsBedModalOpen(false)}>{t('cancel')}</Button>
             <Button type="submit">{editingBedId ? t('edit') : t('add')}</Button>
           </div>
         </form>
      </Modal>

      <Modal isOpen={isFinanceModalOpen} onClose={() => setIsFinanceModalOpen(false)} title={`${editingFinanceId ? t('edit') : t('add')} ${financeTab === 'tax' ? t('config_financial_tax_tab') : t('config_financial_payment_tab')}`}>
        <form onSubmit={handleFinanceSubmit} className="space-y-4">
           <Input label="Name (EN)" required value={financeForm.name_en || ''} onChange={e => setFinanceForm({...financeForm, name_en: e.target.value})} />
           <Input label="Name (AR)" required value={financeForm.name_ar || ''} onChange={e => setFinanceForm({...financeForm, name_ar: e.target.value})} />
           {financeTab === 'tax' && (
             <Input label="Rate (%)" type="number" required value={financeForm.rate || ''} onChange={e => setFinanceForm({...financeForm, rate: e.target.value})} />
           )}
           <div className="flex items-center gap-2"><input type="checkbox" checked={financeForm.isActive !== false} onChange={e => setFinanceForm({...financeForm, isActive: e.target.checked})} /> Active</div>
           <div className="flex justify-end pt-2 gap-3">
             <Button type="button" variant="secondary" onClick={() => setIsFinanceModalOpen(false)}>{t('cancel')}</Button>
             <Button type="submit">{t('save')}</Button>
           </div>
        </form>
      </Modal>

      {/* --- CONFIRMATION DIALOG --- */}
      <ConfirmationDialog 
        isOpen={confirmState.isOpen}
        onClose={() => setConfirmState({ ...confirmState, isOpen: false })}
        onConfirm={() => {
          confirmState.action();
          setConfirmState({ ...confirmState, isOpen: false });
        }}
        title={confirmState.title}
        message={confirmState.message}
        type={confirmState.type || 'danger'}
      />
    </div>
  );
};

import React, { useState, useEffect } from 'react';
