    e.preventDefault();
    setLoading(true);
    setError('');
    try {
      // API returns { token: string, user: User }
      const response = await api.login(username, password);
      login(response.user, response.token);
    } catch (err: any) {
      console.error(err);
      setError(err.response?.data?.error || t('login_error_auth_failed'));
    } finally {
      setLoading(false);
